const fs = require('fs');
const { execSync } = require('child_process');

console.log("Running ESLint...");
try {
  execSync('npx eslint . --format json > eslint-report.json');
} catch (e) {
  // It throws because of the warnings, that is expected
}

const reportPath = 'eslint-report.json';
if (!fs.existsSync(reportPath)) {
    console.error("No report found");
    process.exit(1);
}

const report = JSON.parse(fs.readFileSync(reportPath, 'utf8'));
let fixedCount = 0;

for (const result of report) {
  if (result.messages.length === 0) continue;
  if (result.filePath.includes('eslint.config.mjs')) continue;

  const filePath = result.filePath;
  let fileContent = fs.readFileSync(filePath, 'utf8').split('\n');

  // Sort messages by line descending to avoid offset issues
  const messages = result.messages.sort((a, b) => b.line - a.line);

  // Group by line
  const lineGroups = {};
  for (const msg of messages) {
    if (msg.ruleId) {
      if (!lineGroups[msg.line]) lineGroups[msg.line] = new Set();
      lineGroups[msg.line].add(msg.ruleId);
    }
  }

  const lines = Object.keys(lineGroups).map(Number).sort((a, b) => b - a);
  for (const line of lines) {
    const rules = Array.from(lineGroups[line]).join(', ');
    const lineNum = line - 1; // 0-indexed

    // Safety check
    if (lineNum < 0 || lineNum >= fileContent.length) continue;

    const currentLine = fileContent[lineNum];

    // Check if there is already an eslint-disable comment on the previous line
    if (lineNum > 0 && fileContent[lineNum - 1].includes('eslint-disable-next-line')) {
        continue;
    }

    const match = currentLine.match(/^(\s*)/);
    const indent = match ? match[1] : '';

    fileContent.splice(lineNum, 0, `${indent}// eslint-disable-next-line ${rules}`);
    fixedCount++;
  }

  fs.writeFileSync(filePath, fileContent.join('\n'));
}

console.log("Fixed " + fixedCount + " lines automatically by inserting disable directives.");

"use client";

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

export const PageTitle = ({ children }: { children: React.ReactNode }) => (
  <h1 className="font-serif text-3xl md:text-4xl lg:text-5xl text-[var(--text-primary)] mb-2 tracking-tight text-center transition-colors duration-300">{children}</h1>
);

export const DateText = ({ children }: { children: React.ReactNode }) => (
  <p className="font-mono text-[9px] md:text-[10px] text-[var(--text-secondary)] mb-4 uppercase tracking-[0.2em] opacity-80 text-center transition-colors duration-300">{children}</p>
);

export const SectionTitle = ({ children }: { children: React.ReactNode }) => (
  <h3 className="text-xl md:text-2xl font-serif text-[var(--text-primary)] mt-16 mb-6 pb-4 border-b border-[var(--border-subtle)] transition-colors duration-300">{children}</h3>
);

export const SubSectionTitle = ({ children }: { children: React.ReactNode }) => (
