/**
 * Helper to map between Frontend IDs (hyphenated) and Database IDs (underscored)
 */
const platformMappings: Record<string, string> = {
  'google-calendar': 'google_calendar',
  'google-gmail': 'gmail', // handle legacy or variations
  'twitter': 'twitter',
};

const toDbPlatform = (id: string) => platformMappings[id] || id.replace(/-/g, '_');
const fromDbPlatform = (dbPlatform: string) => {
  for (const [id, dbId] of Object.entries(platformMappings)) {
    if (dbId === dbPlatform) return id;
  }
  return dbPlatform.replace(/_/g, '-');
};

export async function GET() {
  try {
    const supabase = await createClient();
    const { data: authData } = await supabase.auth.getUser();
    const user = authData.user;

    if (!user) {
      return NextResponse.json({ platforms: [] }, { status: 200 });
    }

    // Fetch both OAuth tokens and Sync Status in parallel
    const [{ data: tokens }, { data: syncRows }] = await Promise.all([
      supabase.from('oauth_tokens').select('platform').eq('user_id', user.id),
      supabase.from('sync_status').select('platform, status, sync_progress, total_items, last_sync_at, error_message').eq('user_id', user.id),
    ]);

    const tokenPlatforms = new Set((tokens || []).map(t => t.platform));
    const syncMap = new Map((syncRows || []).map(s => [s.platform, s]));

    console.log(`[Readiness] Loading state for user ${user.id}. Found ${tokenPlatforms.size} tokens and ${syncMap.size} sync records.`);

    const STALE_SYNC_THRESHOLD_MS = 30 * 60 * 1000; // 30 minutes
    const now = Date.now();

    const platforms: PlatformReadiness[] = platformConfigs.map((cfg) => {
      const dbId = toDbPlatform(cfg.id);
      const sync = syncMap.get(dbId);
      const hasToken = tokenPlatforms.has(dbId);

      let status = (sync?.status ?? 'idle') as PlatformReadiness['status'];

      // If a sync is stuck in 'syncing' with no update for >30 min, treat it as 'error'.
      // This self-heals the UI when a cron run crashes mid-sync and never completes.
      if (status === 'syncing' && sync?.last_sync_at) {
        const lastSyncMs = new Date(sync.last_sync_at).getTime();
        if (now - lastSyncMs > STALE_SYNC_THRESHOLD_MS) {
          status = 'error';
        }
      }

      // A platform is truly connected only if:
      // 1. It has a valid OAuth token stored, OR
      // 2. It has a non-stale syncing / connected status
      const connected = hasToken || ['connected', 'syncing'].includes(status);

      const missingEnv = cfg.env.filter((key) => !process.env[key]);
      const configured = missingEnv.length === 0;

      return {
        id: cfg.id,
        name: cfg.name,
        connectionType: cfg.env.some(e => e.includes('TOKEN') || e.includes('KEY')) ? 'APIKey' : 'OAuth',
        requiredScopes: cfg.scopes,
        optional: Boolean(cfg.optional),
        deferred: Boolean(cfg.optional && !configured),
        configured,
        missingEnv,
        connected,
        status,
        syncProgress: sync?.sync_progress ?? 0,
        items: sync?.total_items ?? 0,
        lastSyncAt: sync?.last_sync_at ?? null,
        errorMessage: sync?.error_message ?? null,
      };
    });

    return NextResponse.json({ platforms }, { status: 200 });
  } catch (error) {
    console.error('[Readiness] API Fatal Error:', error);
    return NextResponse.json({ platforms: [], error: 'Internal Server Error' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { cookies } from 'next/headers';
import { upsertSyncStatusSafely, batchUpsertSyncStatus } from '@/utils/supabase/upsert';
import { resolveSyncActor } from '@/utils/sync/actor';
import { waitUntil } from '@vercel/functions';

const SYNC_TIMEOUT_MS = 25000; // Increased timeout for multiple platforms

type SyncOutcome = {
  platform: string;
  routePlatform: string;
  success: boolean;
  status: number | null;
  durationMs: number;
  data?: unknown;
  error?: string;
};

export function toSyncRoutePlatform(platform: string) {
  if (platform === 'google_calendar') return 'google-calendar';
  return platform.replace(/_/g, '-');
}

function isBackgroundMode(request: Request) {
  const background = new URL(request.url).searchParams.get('background');
  if (!background) return false;
  return ['1', 'true', 'yes'].includes(background.toLowerCase());
}

function cookieHeaderValue(cookieStore: Awaited<ReturnType<typeof cookies>>) {
  return cookieStore
    .getAll()
    .map(({ name, value }) => `${name}=${value}`)
    .join('; ');
}

function resolveBaseUrl(request: Request) {
  // If we are on localhost, always use relative or local origin to avoid hitting production
  const host = request.headers.get('host');
  if (host) {
    const protocol = host.includes('localhost') ? 'http' : 'https';
    return `${protocol}://${host}`;
  }

  if (process.env.NEXT_PUBLIC_SITE_URL) {
    return process.env.NEXT_PUBLIC_SITE_URL;
  }

  return 'http://localhost:3000';
}

function parseResponsePayload(rawBody: string) {
  if (!rawBody) return null;

  try {
    return JSON.parse(rawBody);
  } catch {
    return { message: rawBody.slice(0, 300) };
  }
}

/**
 * Support manual sync triggers via browser GET requests
 */
export async function GET(request: Request) {
  return POST(request);
}

/**
 * Unified entry point to sync all connected platforms for the current user.
 */
export async function POST(request: Request) {
  const url = new URL(request.url);
  const depth = url.searchParams.get('depth') || 'shallow';

  try {
    const actor = await resolveSyncActor(request);
    if ('status' in actor) {
      return NextResponse.json({ error: actor.error }, { status: actor.status });
    }

    const { supabase, userId, mode } = actor;

    // Get all connected platforms with valid tokens
    const { data: tokens } = await supabase
      .from('oauth_tokens')
      .select('platform')
      .eq('user_id', userId);

    // Filter out platforms that are missing critical configuration in this environment
    const oauthPlatforms = (tokens ?? []).filter(t => {
      // Check if critical client secrets are missing (Prevents 500s on Vercel)
      if (t.platform === 'github' && !process.env.GITHUB_CLIENT_SECRET) return false;
      if (t.platform.startsWith('google') && !process.env.GOOGLE_CLIENT_SECRET) return false;
      return true;
    });

    const DIRECT_KEY_PLATFORMS: Array<{ platform: string; envKey: string }> = [
      { platform: 'vercel', envKey: 'VERCEL_API_TOKEN' },
      { platform: 'trello', envKey: 'TRELLO_API_KEY' },
      { platform: 'posthog', envKey: 'POSTHOG_API_KEY' },
      { platform: 'devin', envKey: 'DEVIN_API_KEY' },
      { platform: 'cursor', envKey: 'CURSOR_API_KEY' },
    ];

    const directPlatforms = DIRECT_KEY_PLATFORMS
      .filter((p) => Boolean(process.env[p.envKey]))
      .filter((p) => !oauthPlatforms.some((t) => t.platform === p.platform))
      .map((p) => ({ platform: p.platform }));

    const allPlatforms = [...oauthPlatforms, ...directPlatforms];

    if (allPlatforms.length === 0) {
      return NextResponse.json({ message: 'No connected platforms found.', results: [] });
    }

    const appBaseUrl = resolveBaseUrl(request);
    
    // Prepare headers for sub-requests
    const subHeaders: Record<string, string> = {
      'Content-Type': 'application/json',
    };

    if (mode === 'cron') {
      subHeaders['x-cron-secret'] = process.env.CRON_SECRET || '';
      subHeaders['x-cron-user-id'] = userId;
    } else {
      const cookieStore = await cookies();
      subHeaders['Cookie'] = cookieHeaderValue(cookieStore);
    }

    const runPlatformSync = async (platform: string): Promise<SyncOutcome> => {
      const routePlatform = toSyncRoutePlatform(platform);
      const startedAt = Date.now();

      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), SYNC_TIMEOUT_MS);

      try {
        const syncUrl = new URL(`${appBaseUrl}/api/sync/${routePlatform}`);
        syncUrl.searchParams.set('depth', depth);

        const response = await fetch(syncUrl.toString(), {
          method: 'POST',
          headers: subHeaders,
          cache: 'no-store',
          signal: controller.signal,
        });

        const rawBody = await response.text();
        const data = parseResponsePayload(rawBody);

        if (!response.ok) {
          const message = `Provider sync failed (${response.status})`;
          await upsertSyncStatusSafely(supabase, {
            user_id: userId,
            platform,
            status: 'error',
            sync_progress: 0,
            error_message: message,
          });

          return {
            platform,
            routePlatform,
            success: false,
            status: response.status,
            durationMs: Date.now() - startedAt,
            data,
            error: message,
          };
        }

        return {
          platform,
          routePlatform,
          success: true,
          status: response.status,
          durationMs: Date.now() - startedAt,
          data,
        };
      } catch (error) {
        const message = error instanceof Error ? error.message : String(error);
        await upsertSyncStatusSafely(supabase, {
          user_id: userId,
          platform,
          status: 'error',
          sync_progress: 0,
          error_message: message.slice(0, 250),
        });

        return {
          platform,
          routePlatform,
          success: false,
          status: null,
          durationMs: Date.now() - startedAt,
          error: message,
        };
      } finally {
        clearTimeout(timeoutId);
      }
    };

    // Pre-mark all platforms as 'syncing' in a single batch write
    await batchUpsertSyncStatus(supabase, allPlatforms.map((token) => ({
      user_id: userId,
      platform: token.platform,
      status: 'syncing',
      sync_progress: 1,
      error_message: null,
    })));

    // 3. LAUNCH BACKGROUND SYNC (Use waitUntil for Vercel persistence)
    waitUntil(
      Promise.allSettled(allPlatforms.map((token) => runPlatformSync(token.platform))).then((settled) => {
        const fulfilled = settled.filter((item): item is PromiseFulfilledResult<SyncOutcome> => item.status === 'fulfilled');
        const successCount = fulfilled.filter((item) => item.value.success).length;
        const failedCount = fulfilled.length - successCount + (settled.length - fulfilled.length);
        console.log(
          `[Sync All] Background sync complete. user=${userId} success=${successCount} failed=${failedCount}`
        );
      })
    );


    return NextResponse.json(
      {
        accepted: true,
        mode: 'background',
        message: `Sync launched for ${allPlatforms.length} platforms. Check sync_status for progress.`,
        platforms: allPlatforms.map((token) => token.platform),
      },
      { status: 202 }
    );
  } catch (err) {
    console.error('Unified Sync error:', err);
    return NextResponse.json({ error: 'Failed to initiate global sync.' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';

import { upsertRawEventsSafely, upsertSyncStatusSafely } from '@/utils/supabase/upsert';
import { getValidGoogleToken } from '@/services/auth/oauth';
import { scoreGmailEvent } from '@/utils/risk/scorer';
import { resolveSyncActor, type SyncActor, type SyncActorError } from '@/utils/sync/actor';

type GmailListResponse = {
  messages?: Array<{ id: string }>;
};

type GmailMessageResponse = {
  id: string;
  threadId?: string;
  snippet?: string;
  internalDate?: string;
  payload?: {
    headers?: Array<{ name: string; value: string }>;
    body?: {
      data?: string;
    };
    parts?: GmailMessagePart[];
  };
};

type GmailMessagePart = {
  mimeType?: string;
  body?: {
    data?: string;
  };
  parts?: GmailMessagePart[];
};

function getHeader(headers: Array<{ name: string; value: string }> | undefined, key: string) {
  return headers?.find((header) => header.name.toLowerCase() === key.toLowerCase())?.value;
}

// Fix common mojibake (UTF-8 bytes incorrectly decoded as Latin-1 by email clients)
function fixEncoding(text: string): string {
  if (!text) return text;
  try {
    // Check for common UTF-8 start bytes that look like Latin-1 characters (â, ð, Ã)
    if (/[âðÃ]/.test(text)) {
      // Ensure all characters are within the Latin-1 range (0-255)
      // If there are higher characters, it's not pure mojibake
      for (let i = 0; i < text.length; i++) {
        if (text.charCodeAt(i) > 255) return text; 
      }
      const fixed = Buffer.from(text, 'latin1').toString('utf8');
      // If the resulting string has replacement characters, the original wasn't valid UTF-8 bytes
      if (!fixed.includes('')) {
        return fixed;
      }
    }
  } catch (e) {
    // fallback
  }
  return text;
}

function decodeBase64Url(value: string) {
  const normalized = value.replace(/-/g, '+').replace(/_/g, '/');
  const padded = normalized.padEnd(Math.ceil(normalized.length / 4) * 4, '=');
  return Buffer.from(padded, 'base64').toString('utf8');
}

function extractTextFromPart(part: GmailMessagePart | undefined): string {
  if (!part) return '';

  const mimeType = part.mimeType || '';
  const ownText = part.body?.data ? decodeBase64Url(part.body.data) : '';

  if (mimeType.startsWith('text/plain') && ownText) {
    return ownText;
  }

  const nested = (part.parts || []).map(extractTextFromPart).filter(Boolean).join('\n');
  if (nested) return nested;

  if (mimeType.startsWith('text/html') && ownText) {
    return ownText
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
  }

  return ownText;
}

export async function POST(request: Request) {
  if (process.env.MOCK_MODE === 'true') {
    return NextResponse.json({
      ok: true,
      syncedMessages: 3,
      hasMore: false,
    });
  }

  let actor: SyncActor | SyncActorError | null = null;
  try {
    actor = await resolveSyncActor(request);
    if ('status' in actor) {
      return NextResponse.json({ error: actor.error }, { status: actor.status });
    }

    const { supabase, userId } = actor;
    
    // --- DATA LOCKDOWN GUARD ---
    // Prevent ingestion while an Audit is in progress to ensure snapshot integrity
    const { data: activeAudit } = await supabase
      .from('reputation_audits')
      .select('id, status')
      .eq('user_id', userId)
      .in('status', ['pending', 'analysis', 'generating'])
      .maybeSingle();

    if (activeAudit) {
      return NextResponse.json({ 
        error: 'System Busy: Reputation Audit in progress.', 
        detail: 'Ingestion is paused to ensure data snapshot integrity for your current audit.' 
      }, { status: 423 }); // 423 Locked
    }

    // Get User Settings for Sync Depth and Excluded Senders
    const { data: settingsData } = await supabase
      .from('connector_settings')
      .select('data_types')
      .eq('user_id', userId)
      .eq('platform', 'user_global')
      .maybeSingle();

    let syncDepth = 'balanced';
    let excludedSenders: string[] = [];
    if (settingsData?.data_types?.[0]) {
      try {
        const parsedSettings = JSON.parse(settingsData.data_types[0]);
        if (parsedSettings.syncDepth) syncDepth = parsedSettings.syncDepth;
        if (Array.isArray(parsedSettings.excludedSenders)) excludedSenders = parsedSettings.excludedSenders.map((s: string) => s.toLowerCase());
      } catch {}
    }

    // Fetch privacy exclusions from database table (GDPR Privacy Shield Integration)
    const { data: dbExclusions } = await supabase
      .from('privacy_excludes')
      .select('exclude_value')
      .eq('user_id', userId)
      .eq('connector_id', 'gmail')
      .eq('exclude_type', 'email_address');

    if (dbExclusions && dbExclusions.length > 0) {
      const dbExcludedSenders = dbExclusions.map((e: { exclude_value: string }) => e.exclude_value.toLowerCase());
      excludedSenders = Array.from(new Set([...excludedSenders, ...dbExcludedSenders]));
    }

    // 1. Get existing sync status to find the cursor
    const { data: currentStatus } = await supabase
      .from('sync_status')
      .select('cursor, total_items')
      .eq('user_id', userId)
      .eq('platform', 'gmail')
      .maybeSingle();

    const startTime = Date.now();
    const MAX_RUN_TIME = 22000; // 22 seconds (Vercel Hobby limit is 10s, Pro is 60s - 22s is a safe middle ground)
    const maxResultsPerPage = 100;
    const isBackfill = new URL(request.url).searchParams.get('backfill') === 'true';
    // Cap total results per individual run to prevent memory bloat and timeouts
    const maxTotalResults = isBackfill ? 500 : 200;

    // Mark as 'syncing'
    await upsertSyncStatusSafely(supabase, {
      user_id: userId,
      platform: 'gmail',
      status: 'syncing',
      last_sync_at: new Date().toISOString(),
    });

    const accessToken = await getValidGoogleToken(supabase, userId, 'gmail');
    if (!accessToken) {
      return NextResponse.json({ error: 'Gmail session expired and refresh failed.' }, { status: 401 });
    }

    let allMessageIds: string[] = [];
    let nextPageToken: string | undefined = isBackfill
      ? (currentStatus?.cursor || undefined)
      : undefined;
    let hasMore = true;

    // --- PAGINATION LOOP (with safety throttle) ---
    while (allMessageIds.length < maxTotalResults && hasMore) {
      // Check if we are running out of time in the serverless execution window
      if (Date.now() - startTime > MAX_RUN_TIME) {
        console.log(`[Gmail Sync] Approaching timeout (${Date.now() - startTime}ms). Pausing run.`);
        break;
      }

      const fetchUrl = new URL('https://gmail.googleapis.com/gmail/v1/users/me/messages');
      fetchUrl.searchParams.set('maxResults', String(maxResultsPerPage));
      if (syncDepth === 'shallow') {
        fetchUrl.searchParams.set('q', 'newer_than:30d');
      } else if (syncDepth === 'balanced') {
        fetchUrl.searchParams.set('q', 'newer_than:180d');
      }
      if (nextPageToken) fetchUrl.searchParams.set('pageToken', nextPageToken);

      const listResponse = await fetch(fetchUrl.toString(), {
        headers: { Authorization: `Bearer ${accessToken}` },
        cache: 'no-store',
      });

      if (!listResponse.ok) {
        hasMore = false;
        break;
      }

      const listBody = (await listResponse.json()) as { messages?: Array<{ id: string }>, nextPageToken?: string };
      const pageIds = (listBody.messages ?? []).map((m) => m.id);
      allMessageIds = [...allMessageIds, ...pageIds];

      nextPageToken = listBody.nextPageToken;
      if (!nextPageToken) {
        hasMore = false;
        break;
      }
      
      await new Promise(resolve => setTimeout(resolve, 150));
    }

    const messages: GmailMessageResponse[] = [];
    const chunkSize = 25; // 25 requests = 125 quota units (Safe limit is 250/sec)

    // --- RATE LIMIT SHIELD ---
    for (let i = 0; i < allMessageIds.length; i += chunkSize) {
      // Check if we are running out of time
      if (Date.now() - startTime > MAX_RUN_TIME) {
        console.log(`[Gmail Sync] Timeout safety triggered during message fetch (${Date.now() - startTime}ms). Saving progress.`);
        hasMore = true; // Ensure we mark as syncing/hasMore to pick up the cursor later
        break;
      }

      const chunkIds = allMessageIds.slice(i, i + chunkSize);
      let attempt = 0;
      let success = false;

      while (attempt < 3 && !success) {
        try {
          const chunkResponses = await Promise.all(
            chunkIds.map(async (id) => {
              const res = await fetch(`https://gmail.googleapis.com/gmail/v1/users/me/messages/${id}?format=full&metadataHeaders=Subject&metadataHeaders=From`, {
                headers: { Authorization: `Bearer ${accessToken}` },
                cache: 'no-store',
              });
              
              if (res.status === 429) throw new Error('RATE_LIMIT');
              return res.ok ? res.json() : null;
            })
          );
          
          messages.push(...(chunkResponses.filter(Boolean) as GmailMessageResponse[]));
          success = true;
          
          if (i + chunkSize < allMessageIds.length) {
            await new Promise(resolve => setTimeout(resolve, 800)); // Respect Google's 1-sec token bucket
          }
        } catch (err) {
          attempt++;
          console.warn(`[Gmail Sync] Rate limit hit. Backing off (Attempt ${attempt}/3)...`);
          if (attempt >= 3) {
            console.error('[Gmail Sync] Max retries hit. Saving progress and aborting run.');
            break; 
          }
          await new Promise(resolve => setTimeout(resolve, attempt * 2500)); // Exponential backoff: 2.5s, 5s
        }
      }
    }

    const eventsRaw = await Promise.all(messages.map(async (message) => {
      const subject = fixEncoding(getHeader(message.payload?.headers, 'Subject') || 'No subject');
      const fromRaw = getHeader(message.payload?.headers, 'From') || 'Unknown sender';
      const from = fixEncoding(fromRaw);

      // Privacy Shield: Drop excluded senders
      if (excludedSenders.some(ex => from.toLowerCase().includes(ex))) {
        return null; // Ignore this email
      }
      const bodyText = fixEncoding(extractTextFromPart({
        mimeType: 'multipart/mixed',
        body: message.payload?.body,
        parts: message.payload?.parts,
      }));
      const snippet = fixEncoding(message.snippet || '');
      
      const content = `${subject}\n${snippet}\n${bodyText}`.trim().slice(0, 12000);
      const ts = message.internalDate ? new Date(Number(message.internalDate)).toISOString() : new Date().toISOString();
      const risk = await scoreGmailEvent({
        subject,
        snippet: `${snippet} ${bodyText.slice(0, 1500)}`.trim(),
        from,
      });

      return {
        user_id: userId,
        platform: 'gmail',
        platform_id: message.id,
        event_type: 'email',
        title: subject,
        content,
        author: from,
        timestamp: ts,
        metadata: {
          from,
          snippet: message.snippet || null,
          body_indexed: bodyText.length > 0,
          risk_score: risk.score,
          risk_factors: risk.reasons,
          thread_id: message.threadId || null,
        },
        is_flagged: risk.flagged,
        flag_severity: risk.severity,
        flag_reason: risk.reasons[0] || null,
      };
    }));

    // Filter out dropped emails from privacy shields
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const events = eventsRaw.filter(Boolean) as any[];

    // upsertRawEventsSafely: stores to unified memories table
    await upsertRawEventsSafely(supabase, events);
    console.log(`[Gmail Sync] Upserted ${events.length} events for user ${userId}`);

    // Trigger action extraction and Resend draft approval email hook if we got new emails
    if (events.length > 0) {
      try {
        console.log(`[Gmail Sync] Triggering action extraction for user ${userId}`);
        const { extractForUser } = await import('@/app/api/actions/extract/route');
        
        const { data: beforeActions } = await supabase
          .from('action_queue')
          .select('id')
          .eq('user_id', userId)
          .eq('status', 'pending');
        const beforeIds = new Set((beforeActions ?? []).map((a: { id: string }) => a.id));

        await extractForUser(userId, supabase);

        const { data: afterActions } = await supabase
          .from('action_queue')
          .select('*')
          .eq('user_id', userId)
          .eq('status', 'pending');

        const newActions = (afterActions ?? []).filter((a: { id: string }) => !beforeIds.has(a.id));
        const emailReplies = newActions.filter((a: { action_type: string }) => a.action_type === 'EMAIL_REPLY');
        
        if (emailReplies.length > 0) {
          const { sendDraftApprovalEmail } = await import('@/services/email/resend');
          const { data: profile } = await supabase
            .from('user_profiles')
            .select('email, name')
            .eq('user_id', userId)
            .maybeSingle();

          if (profile?.email) {
            for (const reply of emailReplies) {
              const bodyText = reply.suggested_action || reply.description || '';
              const citationsText = reply.description || 'No citations context provided.';
              const author = reply.platform === 'gmail' && reply.memory_id ? 
                (events.find(e => e.platform_id === reply.memory_id)?.author || 'Sender') : 'Sender';

              await sendDraftApprovalEmail({
                to: profile.email,
                name: profile.name || 'User',
                sender: author,
                summary: reply.title || 'Incoming email',
                draftReply: bodyText,
                citations: citationsText,
                actionId: reply.id
              });
            }
          }
        }
      } catch (extractErr) {
        console.error('[Gmail Sync] Action extraction/notification hook failed:', extractErr);
      }
    }

    // Save the new cursor (nextPageToken) back to Supabase
    // Count actual total memories across ALL platforms for this user (prevents reset on reconnect)
    const { count: actualTotalMemories } = await supabase
      .from('memories')
      .select('id', { count: 'exact', head: true })
      .eq('user_id', userId);

    await Promise.all([
      upsertSyncStatusSafely(supabase, {
        user_id: userId,
        platform: 'gmail',
        status: hasMore ? 'syncing' : 'connected',
        sync_progress: hasMore ? 50 : 100,
        total_items: (currentStatus?.total_items || 0) + events.length,
        last_sync_at: new Date().toISOString(),
        next_sync_at: new Date(Date.now() + 1000 * 60 * 30).toISOString(),
        cursor: hasMore ? nextPageToken : null,
        error_message: null,
      }),
      supabase.from('user_profiles').update({
        // Use actual DB count — not sync_status.total_items which resets on OAuth reconnection
        memories_indexed: actualTotalMemories ?? 0,
        updated_at: new Date().toISOString(),
      }).eq('user_id', userId),
    ]);

    return NextResponse.json({
      ok: true,
      syncedMessages: events.length,
      hasMore,
    });
  } catch (error: unknown) {
    const detail = error instanceof Error ? error.message : String(error);
    console.error('gmail sync error:', error);

    // CRITICAL: Reset status in DB so UI is not frozen
    if (actor && 'supabase' in actor) {
      await upsertSyncStatusSafely(actor.supabase, {
        user_id: actor.userId,
        platform: 'gmail',
        status: 'error',
        error_message: detail.slice(0, 200)
      });
    }

    return NextResponse.json({ 
      error: 'Unable to sync Gmail data.', 
      detail
    }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';

import { getValidGoogleToken } from '@/services/auth/oauth';
import { upsertRawEventsSafely, upsertSyncStatusSafely } from '@/utils/supabase/upsert';
import { resolveSyncActor } from '@/utils/sync/actor';

type CalendarEventsResponse = {
  items?: Array<{
    id: string;
    summary?: string;
    description?: string;
    creator?: { email?: string };
    start?: { dateTime?: string; date?: string };
    end?: { dateTime?: string; date?: string };
    htmlLink?: string;
  }>;
};

export async function POST(request: Request) {
  if (process.env.MOCK_MODE === 'true') {
    return NextResponse.json({
      ok: true,
      syncedEvents: 2,
      totalMemories: 3,
      hasMore: false,
    });
  }

  try {
    const actor = await resolveSyncActor(request);
    if ('status' in actor) {
      return NextResponse.json({ error: actor.error }, { status: actor.status });
    }

    const { supabase, userId } = actor;

    // 1. Get existing sync status to find the cursor
    const { data: currentStatus } = await supabase
      .from('sync_status')
      .select('cursor, total_items')
      .eq('user_id', userId)
      .eq('platform', 'google_calendar')
      .maybeSingle();

    const accessToken = await getValidGoogleToken(supabase, userId, 'google_calendar');
    if (!accessToken) {
      return NextResponse.json({ error: 'Google Calendar session expired and refresh failed.' }, { status: 401 });
    }

    const url = new URL(request.url);
    const depth = url.searchParams.get('depth') || 'shallow';
    const maxResults = depth === 'deep' ? 500 : 50;
    const historyDays = depth === 'deep' ? 1095 : 180; // 3 years vs 6 months
    const timeMin = new Date(Date.now() - 1000 * 60 * 60 * 24 * historyDays).toISOString();

    // Mark as 'syncing'
    await upsertSyncStatusSafely(supabase, {
      user_id: userId,
      platform: 'google_calendar',
      status: 'syncing',
      last_sync_at: new Date().toISOString(),
    });

    interface CalendarItem {
      id: string;
      summary?: string;
      description?: string;
      creator?: { email?: string };
      start?: { dateTime?: string; date?: string };
      end?: { dateTime?: string; date?: string };
      htmlLink?: string;
    }
    interface CalendarListResponse {
      items?: CalendarItem[];
      nextPageToken?: string;
    }

    let allEvents: CalendarItem[] = [];
    let nextPageToken: string | undefined = currentStatus?.cursor || undefined;
    let hasMore = true;

    // --- PAGINATION LOOP ---
    // Fetch a batch of events
    const fetchUrl = new URL('https://www.googleapis.com/calendar/v3/calendars/primary/events');
    fetchUrl.searchParams.set('maxResults', maxResults.toString());
    fetchUrl.searchParams.set('singleEvents', 'true');
    fetchUrl.searchParams.set('orderBy', 'startTime');
    fetchUrl.searchParams.set('timeMin', timeMin);
    if (nextPageToken) fetchUrl.searchParams.set('pageToken', nextPageToken);

    const response = await fetch(fetchUrl.toString(), {
      headers: { Authorization: `Bearer ${accessToken}` },
      cache: 'no-store',
    });

    if (!response.ok) {
      const providerError = await response.text();
      return NextResponse.json({ 
        error: `Calendar API failed (${response.status})`, 
        detail: providerError.slice(0, 300) 
      }, { status: 502 });
    }

    const body = (await response.json()) as CalendarListResponse;
    allEvents = body.items ?? [];
    nextPageToken = body.nextPageToken;
    hasMore = !!nextPageToken;

    const events = allEvents.map((item) => {
      const title = item.summary || 'Untitled event';
      const description = item.description || '';
      const ts = item.start?.dateTime || item.start?.date || new Date().toISOString();
      const content = `${title} ${description}`.trim();
      const isFlagged = /interview|confidential|medical|legal/i.test(content);

      return {
        user_id: userId,
        platform: 'google_calendar',
        platform_id: item.id,
        event_type: 'calendar_event',
        title,
        content,
        author: item.creator?.email || 'Google Calendar',
        timestamp: new Date(ts).toISOString(),
        metadata: {
          start: item.start,
          end: item.end,
          htmlLink: item.htmlLink,
        },
        is_flagged: isFlagged,
        flag_severity: isFlagged ? 'LOW' : 'LOW',
        flag_reason: isFlagged ? 'Potentially sensitive calendar event' : null,
      };
    });

    await upsertRawEventsSafely(supabase, events);

    const { count: totalMemories } = await supabase
      .from('memories')
      .select('id', { count: 'exact', head: true })
      .eq('user_id', userId);

    // Update status and save cursor
    const [, profileUpdate] = await Promise.all([
      upsertSyncStatusSafely(supabase, {
        user_id: userId,
        platform: 'google_calendar',
        status: hasMore ? 'syncing' : 'connected',
        sync_progress: hasMore ? 50 : 100,
        total_items: (currentStatus?.total_items || 0) + events.length,
        last_sync_at: new Date().toISOString(),
        next_sync_at: new Date(Date.now() + 1000 * 60 * 30).toISOString(),
        cursor: hasMore ? nextPageToken : null,
        error_message: null,
      }),
      supabase.from('user_profiles').update({
        memories_indexed: totalMemories ?? events.length,
        updated_at: new Date().toISOString(),
      }).eq('user_id', userId),
    ]);

    if (profileUpdate.error) throw profileUpdate.error;

    return NextResponse.json({ 
      ok: true, 
      syncedEvents: events.length,
      totalMemories,
      hasMore 
    });
  } catch (error) {
    console.error('google-calendar sync error:', error);
    return NextResponse.json({ error: 'Unable to sync Google Calendar data right now.' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';

import { upsertRawEventsSafely, upsertSyncStatusSafely } from '@/utils/supabase/upsert';
import { decryptToken } from '@/services/auth/tokens';
import { resolveSyncActor } from '@/utils/sync/actor';
import { scoreNotionEvent } from '@/utils/risk/scorer';

type NotionSearchResult = {
  id: string;
  object: 'page' | 'database' | string;
  url?: string;
  last_edited_time?: string;
  properties?: Record<string, { type?: string; title?: Array<{ plain_text: string }> }>;
  title?: Array<{ plain_text: string }>;
};

type NotionSearchResponse = {
  results?: NotionSearchResult[];
};

type NotionBlock = {
  id: string;
  type: string;
  has_children?: boolean;
  rich_text?: Array<{ plain_text?: string }>;
  paragraph?: { rich_text?: Array<{ plain_text?: string }> };
  heading_1?: { rich_text?: Array<{ plain_text?: string }> };
  heading_2?: { rich_text?: Array<{ plain_text?: string }> };
  heading_3?: { rich_text?: Array<{ plain_text?: string }> };
  bulleted_list_item?: { rich_text?: Array<{ plain_text?: string }> };
  numbered_list_item?: { rich_text?: Array<{ plain_text?: string }> };
  to_do?: { rich_text?: Array<{ plain_text?: string }> };
  quote?: { rich_text?: Array<{ plain_text?: string }> };
  callout?: { rich_text?: Array<{ plain_text?: string }> };
  code?: { rich_text?: Array<{ plain_text?: string }> };
};

function extractRichText(parts: Array<{ plain_text?: string }> | undefined) {
  return (parts || []).map((part) => part.plain_text || '').join(' ').trim();
}

function extractBlockText(block: NotionBlock) {
  const blockRecord = block as Record<string, unknown>;
  const typePayload = blockRecord[block.type] as { rich_text?: Array<{ plain_text?: string }> } | undefined;
  return extractRichText(typePayload?.rich_text || block.rich_text);
}

async function fetchNotionPageContent(accessToken: string, pageId: string) {
  const response = await fetch(`https://api.notion.com/v1/blocks/${pageId}/children?page_size=100`, {
    headers: {
      Authorization: `Bearer ${accessToken}`,
      'Notion-Version': '2022-06-28',
      'Content-Type': 'application/json',
    },
    cache: 'no-store',
  });

  if (!response.ok) {
    return '';
  }

  const body = (await response.json()) as { results?: NotionBlock[] };
  return (body.results || []).map(extractBlockText).filter(Boolean).join('\n').slice(0, 10000);
}

function extractTitle(item: NotionSearchResult) {
  if (item.object === 'database' && item.title?.length) {
    return item.title.map((part) => part.plain_text).join(' ').trim() || 'Untitled database';
  }

  if (item.object === 'page' && item.properties) {
    const titleProperty = Object.values(item.properties).find((property) => property?.type === 'title');
    if (titleProperty?.title?.length) {
      return titleProperty.title.map((part) => part.plain_text).join(' ').trim() || 'Untitled page';
    }
  }

  return item.object === 'database' ? 'Untitled database' : 'Untitled page';
}

export async function POST(request: Request) {
  try {
    const actor = await resolveSyncActor(request);
    if ('status' in actor) {
      return NextResponse.json({ error: actor.error }, { status: actor.status });
    }

    const { supabase, userId } = actor;

    // 1. Get existing sync status to find the cursor
    const { data: currentStatus } = await supabase
      .from('sync_status')
      .select('cursor, total_items')
      .eq('user_id', userId)
      .eq('platform', 'notion')
      .maybeSingle();

    const { data: tokenRow } = await supabase
      .from('oauth_tokens')
      .select('access_token')
      .eq('user_id', userId)
      .eq('platform', 'notion')
      .maybeSingle();

    if (!tokenRow?.access_token) {
      return NextResponse.json({ error: 'Notion is not connected yet.' }, { status: 400 });
    }

    const decryptedToken = decryptToken(tokenRow.access_token);
    if (!decryptedToken) {
      console.error('notion sync auth error: token invalid or corrupted');
      return NextResponse.json({ error: 'Unable to authenticate Notion connection.' }, { status: 401 });
    }
    const accessToken = decryptedToken;

    const url = new URL(request.url);
    const depth = url.searchParams.get('depth') || 'shallow';
    const maxResultsPerPage = 100;
    const maxTotalResults = depth === 'deep' ? 500 : 50;

    // Mark as 'syncing'
    await upsertSyncStatusSafely(supabase, {
      user_id: userId,
      platform: 'notion',
      status: 'syncing',
      last_sync_at: new Date().toISOString(),
    });

    let allResults: NotionSearchResult[] = [];
    let nextCursor: string | undefined = currentStatus?.cursor || undefined;
    let hasMore = true;

    // --- PAGINATION LOOP ---
    while (allResults.length < maxTotalResults && hasMore) {
      const searchResponse = await fetch('https://api.notion.com/v1/search', {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${accessToken}`,
          'Notion-Version': '2022-06-28',
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ 
          page_size: Math.min(maxResultsPerPage, maxTotalResults - allResults.length),
          start_cursor: nextCursor,
          sort: {
            direction: 'descending',
            timestamp: 'last_edited_time'
          }
        }),
        cache: 'no-store',
      });

      if (!searchResponse.ok) {
        if (searchResponse.status === 401 || searchResponse.status === 403) {
          const detail = await searchResponse.text();
          throw new Error(`Notion auth failed: ${searchResponse.status} ${detail}`);
        }

        hasMore = false;
        break;
      }

      const body = (await searchResponse.json()) as { results?: NotionSearchResult[], next_cursor?: string | null };
      const pageResults = body.results ?? [];
      allResults = [...allResults, ...pageResults];
      
      nextCursor = body.next_cursor || undefined;
      if (!nextCursor) {
        hasMore = false;
        break;
      }
    }

    const events = await Promise.all(allResults.map(async (item) => {
      const title = extractTitle(item);
      const pageContent = item.object === 'page'
        ? await fetchNotionPageContent(accessToken, item.id)
        : '';
      const content = `${title}\n${pageContent}\n${item.url || ''}`.trim().slice(0, 12000);
      const risk = await scoreNotionEvent({ title, content });

      return {
        user_id: userId,
        platform: 'notion',
        platform_id: item.id,
        event_type: item.object,
        title,
        content,
        author: 'Notion',
        timestamp: item.last_edited_time ? new Date(item.last_edited_time).toISOString() : new Date().toISOString(),
        metadata: {
          object: item.object,
          url: item.url,
          page_content_indexed: pageContent.length > 0,
        },
        is_flagged: risk.flagged,
        flag_severity: risk.severity,
        flag_reason: risk.reasons.join(', '),
      };
    }));

    await upsertRawEventsSafely(supabase, events);

    // Update status and save cursor
    await Promise.all([
      upsertSyncStatusSafely(supabase, {
        user_id: userId,
        platform: 'notion',
        status: hasMore ? 'syncing' : 'connected',
        sync_progress: hasMore ? 50 : 100,
        total_items: (currentStatus?.total_items || 0) + events.length,
        last_sync_at: new Date().toISOString(),
        next_sync_at: new Date(Date.now() + 1000 * 60 * 30).toISOString(),
        cursor: hasMore ? nextCursor : null,
        error_message: null,
      }),
      supabase.from('user_profiles').update({
        // Use cumulative total — not just current batch
        memories_indexed: (currentStatus?.total_items || 0) + events.length,
        updated_at: new Date().toISOString(),
      }).eq('user_id', userId),
    ]);

    return NextResponse.json({
      ok: true,
      syncedItems: events.length,
      hasMore,
    });
  } catch (error) {
    console.error('notion sync error:', error);
    return NextResponse.json({ error: 'Unable to sync Notion data right now.' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';

import { upsertRawEventsSafely, upsertSyncStatusSafely } from '@/utils/supabase/upsert';
import { getValidRedditToken } from '@/services/auth/oauth';
import { scoreRedditEvent } from '@/utils/risk/scorer';
import { resolveSyncActor } from '@/utils/sync/actor';

type RedditMe = { name: string };

type RedditCommentListing = {
  data?: {
    children?: Array<{
      data: {
        id: string;
        name: string;
        body?: string;
        subreddit?: string;
        permalink?: string;
        score?: number;
        created_utc?: number;
      };
    }>;
  };
};

export async function POST(request: Request) {
  try {
    const actor = await resolveSyncActor(request);
    if ('status' in actor) {
      return NextResponse.json({ error: actor.error }, { status: actor.status });
    }

    const { supabase, userId } = actor;

    const { data: currentStatus } = await supabase
      .from('sync_status')
      .select('cursor, total_items')
      .eq('user_id', userId)
      .eq('platform', 'reddit')
      .maybeSingle();

    await upsertSyncStatusSafely(supabase, {
      user_id: userId,
      platform: 'reddit',
      status: 'syncing',
      last_sync_at: new Date().toISOString(),
    });

    const accessToken = await getValidRedditToken(supabase, userId);
    if (!accessToken) {
      return NextResponse.json({ error: 'Reddit session expired and refresh failed.' }, { status: 401 });
    }

    const meResponse = await fetch('https://oauth.reddit.com/api/v1/me', {
      headers: {
        Authorization: `Bearer ${accessToken}`,
        'User-Agent': 'the-eyes/1.0',
      },
      cache: 'no-store',
    });

    if (!meResponse.ok) {
      return NextResponse.json({ error: `Reddit profile request failed (${meResponse.status})` }, { status: 502 });
    }

    const me = (await meResponse.json()) as RedditMe;

    const url = new URL(request.url);
    const depth = url.searchParams.get('depth') || 'shallow';
    const maxTotalRequests = depth === 'deep' ? 1000 : 25;
    
    interface RedditChild {
      data: {
        id: string;
        name: string;
        body?: string;
        subreddit?: string;
        permalink?: string;
        score?: number;
        created_utc?: number;
      };
    }
    interface RedditCommentPage {
      data?: { children?: RedditChild[]; after?: string | null };
    }

    let allChildren: RedditChild[] = [];
    let afterToken: string | undefined = currentStatus?.cursor || undefined;
    let hasMore = true;

    // --- PAGINATION LOOP ---
    while (allChildren.length < maxTotalRequests && hasMore) {
      const fetchUrl = new URL(`https://oauth.reddit.com/user/${me.name}/comments`);
      fetchUrl.searchParams.set('limit', '50');
      if (afterToken) fetchUrl.searchParams.set('after', afterToken);

      const commentsResponse = await fetch(fetchUrl.toString(), {
        headers: {
          Authorization: `Bearer ${accessToken}`,
          'User-Agent': 'the-eyes/1.0',
        },
        cache: 'no-store',
      });

      if (!commentsResponse.ok) {
        hasMore = false;
        break;
      }

      const body = (await commentsResponse.json()) as RedditCommentPage;
      const children = body.data?.children ?? [];
      allChildren = [...allChildren, ...children];
      
      afterToken = body.data?.after || undefined;
      if (!afterToken) {
        hasMore = false;
        break;
      }
      
      // Respect Reddit API rate limit (1 req/sec)
      await new Promise(resolve => setTimeout(resolve, 1000));
    }

    const events = await Promise.all(allChildren.map(async (entry) => {
      const data = entry.data;
      const content = data.body || '';
      const risk = await scoreRedditEvent({
        body: content,
        subreddit: data.subreddit || '',
        score: data.score,
      });

      return {
        user_id: userId,
        platform: 'reddit',
        platform_id: data.name || data.id,
        event_type: 'comment',
        title: `r/${data.subreddit || 'unknown'} comment`,
        content,
        author: me.name,
        timestamp: data.created_utc ? new Date(data.created_utc * 1000).toISOString() : new Date().toISOString(),
        metadata: {
          subreddit: data.subreddit,
          permalink: data.permalink,
          score: data.score,
          risk_score: risk.score,
          risk_factors: risk.reasons,
        },
        is_flagged: risk.flagged,
        flag_severity: risk.severity,
        flag_reason: risk.reasons[0] || null,
      };
    }));

    await upsertRawEventsSafely(supabase, events);

    const { count: totalMemories } = await supabase
      .from('memories')
      .select('id', { count: 'exact', head: true })
      .eq('user_id', userId);

    const [, profileUpdate] = await Promise.all([
      upsertSyncStatusSafely(supabase, {
        user_id: userId,
        platform: 'reddit',
        status: hasMore ? 'syncing' : 'connected',
        sync_progress: hasMore ? 50 : 100,
        total_items: (currentStatus?.total_items || 0) + events.length,
        last_sync_at: new Date().toISOString(),
        next_sync_at: new Date(Date.now() + 1000 * 60 * 60).toISOString(),
        cursor: hasMore ? afterToken : null,
        error_message: null,
      }),
      supabase.from('user_profiles').update({
        memories_indexed: totalMemories ?? events.length,
        updated_at: new Date().toISOString(),
      }).eq('user_id', userId),
    ]);

    if (profileUpdate.error) {
      throw profileUpdate.error;
    }

    return NextResponse.json({ 
      ok: true, 
      syncedComments: events.length,
      hasMore 
    });
  } catch (error) {
    console.error('reddit sync error:', error);
    return NextResponse.json({ error: 'Unable to sync Reddit data right now.' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { generateEmbedding } from '@/services/ai/ai';

/**
 * Re-index: Regenerates embeddings for all memories that lack an embedding.
 * Reads from the unified `memories` table. Processes up to 200 items per call.
 */
export async function POST(request: Request) {
  try {
    const supabase = await createClient();
    const { data: { user }, error: authError } = await supabase.auth.getUser();

    if (authError || !user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // 1. Get raw events that don't have a matching 768d embedding yet
    // Or just all events if we want to be thorough
    const { data: events, error: fetchError } = await supabase
      .from('memories')
      .select('id, content')
      .eq('user_id', user.id)
      .is('embedding', null)
      .not('content', 'is', null)
      .limit(200);

    if (fetchError || !events) {
      throw new Error(`Failed to fetch memories for re-indexing: ${fetchError?.message}`);
    }

    console.log(`[Re-index] Processing ${events.length} memories for user ${user.id}`);

    let successCount = 0;
    const errors = [];

    for (const event of events) {
      try {
        const result = await generateEmbedding(event.content);
        if (result && typeof result !== 'string' && 'embedding' in result && result.embedding) {
          const { error: updateError } = await supabase
            .from('memories')
            .update({ embedding: result.embedding })
            .eq('id', event.id);

          if (updateError) throw updateError;
          successCount++;
        }
      } catch (err) {
        errors.push({ id: event.id, error: String(err) });
      }
    }

    return NextResponse.json({
      success: true,
      processed: events.length,
      successCount,
      errors: errors.length > 0 ? errors : null,
      message: `Re-indexing complete for ${successCount} records.`
    });

  } catch (err) {
    console.error('[Re-index API] Failure:', err);
    return NextResponse.json({ error: 'Failed to re-index memories.' }, { status: 500 });
  }
}

