export function AIIntegrationView({ onBack }: AIIntegrationViewProps) {
  const [dragActive, setDragActive] = useState(false);
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncProgress, setSyncProgress] = useState(0);
  const [syncStatus, setSyncStatus] = useState('');
  const [recentImports, setRecentImports] = useState<Array<{ name: string; platform: string; count: number; date: string; status: 'Completed' | 'Processing' | 'Error' }>>([]);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      setUploadedFile(e.dataTransfer.files[0]);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setUploadedFile(e.target.files[0]);
    }
  };

  const handleStartSync = async () => {
    if (!uploadedFile) return;
    setIsSyncing(true);
    setSyncProgress(0);
    setSyncStatus('Reading upload file...');

    try {
      let rawText = '';
      const fileName = uploadedFile.name;

      if (fileName.endsWith('.zip')) {
        setSyncStatus('Extracting ZIP file...');
        const zip = await JSZip.loadAsync(uploadedFile);

        let jsonFile = Object.values(zip.files).find(f => f.name.endsWith('conversations.json') && !f.dir);
        if (!jsonFile) {
          jsonFile = Object.values(zip.files).find(f => f.name.endsWith('.json') && !f.dir);
        }

        if (!jsonFile) {
          throw new Error('No JSON files found inside the ZIP archive.');
        }
        rawText = await jsonFile.async('text');
      } else if (fileName.endsWith('.json')) {
        rawText = await new Promise<string>((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = (e) => resolve(e.target?.result as string);
          reader.onerror = () => reject(new Error('Failed to read JSON file.'));
          reader.readAsText(uploadedFile);
        });
      } else {
        throw new Error('Unsupported file format. Please upload a .zip or .json file.');
      }

      setSyncStatus('Parsing conversation data...');
      const rawData = JSON.parse(rawText) as unknown[];

      if (!Array.isArray(rawData)) {
        throw new Error('Invalid export format. Expected a JSON array of conversations.');
      }

      let platform = '';
      const memories: ImportMemoryPayload[] = [];

      if (rawData.length > 0 && rawData[0] !== null && typeof rawData[0] === 'object' && ('mapping' in rawData[0] || 'create_time' in rawData[0])) {
        platform = 'chatgpt';
        setSyncStatus('Auto-detected ChatGPT format. Extracting dialogues...');

        for (const convo of rawData as Record<string, unknown>[]) {
          const title = (convo.title as string) || 'Untitled Conversation';
          const mapping = convo.mapping as Record<string, ChatGPTMessagePart> | undefined;
          if (!mapping) continue;

          const nodes = Object.values(mapping);
          const messages = nodes
            .filter((node): node is ChatGPTMessagePart & { message: { content: { parts: unknown[] } } } => 
              !!node.message && !!node.message.content && Array.isArray(node.message.content.parts)
            )
            .sort((a, b) => (a.message.create_time || 0) - (b.message.create_time || 0));

          if (messages.length === 0) continue;

          let dialogue = '';
          for (const msg of messages) {
            const role = msg.message.author?.role === 'user' ? 'User' : 'Assistant';
            const text = (msg.message.content.parts || [])
              .filter((part): part is string => typeof part === 'string')
              .join('\n');
            if (!text.trim()) continue;
            dialogue += `${role}: ${text}\n\n`;
          }

          if (!dialogue.trim()) continue;

          const firstMsgTime = messages[0]?.message?.create_time;
          const timestamp = firstMsgTime ? new Date(firstMsgTime * 1000).toISOString() : new Date().toISOString();

          memories.push({
            source_id: (convo.id as string) || (convo.conversation_id as string) || Math.random().toString(36).substring(7),
            event_type: 'chat_session',
            title,
            content: dialogue.trim(),
            author: 'user',
            timestamp,
            metadata: {
              message_count: messages.length,
              imported_at: new Date().toISOString()
            }
          });
        }

      } else if (rawData.length > 0 && rawData[0] !== null && typeof rawData[0] === 'object' && ('chat_messages' in rawData[0] || 'uuid' in rawData[0])) {
        platform = 'claude';
        setSyncStatus('Auto-detected Claude format. Extracting dialogues...');

        for (const convo of rawData as ClaudeConversation[]) {
          const title = convo.name || 'Untitled Conversation';
          const chatMessages = convo.chat_messages || [];
          if (chatMessages.length === 0) continue;

          let dialogue = '';
          for (const msg of chatMessages) {
            const role = msg.sender === 'human' ? 'User' : 'Assistant';
            const text = msg.text || '';
            if (!text.trim()) continue;
            dialogue += `${role}: ${text}\n\n`;
          }

          if (!dialogue.trim()) continue;

          const timestamp = convo.created_at || new Date().toISOString();

          memories.push({
            source_id: convo.uuid || Math.random().toString(36).substring(7),
            event_type: 'chat_session',
            title,
            content: dialogue.trim(),
            author: 'user',
            timestamp,
            metadata: {
              message_count: chatMessages.length,
              imported_at: new Date().toISOString()
            }
          });
        }
      } else {
        throw new Error('Could not identify the conversation export format.');
      }

      if (memories.length === 0) {
        throw new Error('No valid conversations with messages found in the file.');
      }

      setSyncStatus(`Syncing ${memories.length} conversations to your vault...`);

      const BATCH_SIZE = 30;
      let insertedCount = 0;

      for (let i = 0; i < memories.length; i += BATCH_SIZE) {
        const batch = memories.slice(i, i + BATCH_SIZE);
        const progress = Math.min(Math.round((i / memories.length) * 100), 98);
        setSyncProgress(progress);
        setSyncStatus(`Syncing conversations ${i + 1} to ${Math.min(i + BATCH_SIZE, memories.length)}...`);

        const res = await fetch('/api/user/import', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ platform, memories: batch })
        });

        if (!res.ok) {
          const errData = (await res.json().catch(() => ({}))) as { error?: string };
          throw new Error(errData.error || 'Server error syncing data');
        }

        const resData = (await res.json()) as { inserted?: number };
        insertedCount += (resData.inserted || 0);
      }

      setSyncProgress(100);
      setSyncStatus(`Sync complete! Successfully imported ${insertedCount} conversations.`);
      setUploadedFile(null);

      // Notify other views that a background sync or import was completed
      window.dispatchEvent(new CustomEvent('eyes-realtime-refresh'));

      loadImportsList();

    } catch (err) {
      console.error('[Import Error]', err);
      const errMsg = err instanceof Error ? err.message : 'Failed to complete import.';
      setSyncStatus(`Error: ${errMsg}`);
      setSyncProgress(0);
    } finally {
      setIsSyncing(false);
    }
  };

  const loadImportsList = () => {
    fetch('/api/sync/status')
      .then(res => res.ok ? res.json() : null)
      .then(data => {
        if (!data || !Array.isArray(data.platforms)) return;
        const manualPlatforms = data.platforms.filter(
          (p: { platform: string }) => p.platform === 'chatgpt' || p.platform === 'claude'
        );
        const mappedImports = manualPlatforms.map((p: { platform: string; total_items?: number; last_sync_at?: string; status?: string }) => ({
          name: p.platform === 'chatgpt' ? 'chatgpt_history' : 'claude_history',
          platform: p.platform === 'chatgpt' ? 'ChatGPT' : 'Claude',
          count: p.total_items || 0,
          date: p.last_sync_at ? new Date(p.last_sync_at).toLocaleDateString() + ' ' + new Date(p.last_sync_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : 'Unknown date',
          status: p.status === 'connected' ? 'Completed' as const : p.status === 'error' ? 'Error' as const : 'Processing' as const
        }));
        setRecentImports(mappedImports);
      })
      .catch(() => {});
  };

  useEffect(() => {
    loadImportsList();
  }, []);

  return (
    <div className={styles.container}>
      <div className={styles.panel}>
        <div className={styles.integrationsHeader}>
          <h1 className={styles.title}>AI Integration</h1>
          <span className={styles.betaBadge}>Beta</span>
        </div>
        <p className={styles.subtitle}>Upload your conversation history exports from ChatGPT or Claude. EYES will parse these files and instantly add your past conversations to your vault context.</p>

        <div 
          className={`${styles.uploadZone} ${dragActive ? styles.uploadZoneDragActive : ''}`}
          onDragEnter={handleDrag}
          onDragLeave={handleDrag}
          onDragOver={handleDrag}
          onDrop={handleDrop}
        >
          <input 
            type="file"
            id="file-upload-dashboard"
            style={{ display: 'none' }}
            accept=".zip,.json"
            onChange={handleFileChange}
            disabled={isSyncing}
          />

          {uploadedFile ? (
            <div className={styles.uploadedFileContainer}>
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="var(--accent-primary)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path>
                <polyline points="14 2 14 8 20 8"></polyline>
                <line x1="16" y1="13" x2="8" y2="13"></line>
                <line x1="16" y1="17" x2="8" y2="17"></line>
                <polyline points="10 9 9 9 8 9"></polyline>
              </svg>
              <span className={styles.fileName}>{uploadedFile.name}</span>
              <span className={styles.fileSize}>{(uploadedFile.size / 1024 / 1024).toFixed(2)} MB</span>

              {!isSyncing && (
                <div className={styles.actionBtnRow}>
                  <button className={styles.saveBtn} onClick={handleStartSync}>Start Syncing</button>
                  <button className={styles.cancelBtn} onClick={() => setUploadedFile(null)}>Cancel</button>
                </div>
              )}
            </div>
          ) : !isSyncing ? (
            <div style={{ textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="var(--text-secondary)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ marginBottom: '8px' }}>
                <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
                <polyline points="17 8 12 3 7 8"></polyline>
                <line x1="12" y1="3" x2="12" y2="15"></line>
              </svg>
              <span className={styles.uploadTitle}>Drag and drop your export file here</span>
              <span className={styles.uploadDesc}>Supports .zip (ChatGPT) or .json (Claude)</span>
              <label htmlFor="file-upload-dashboard" className={styles.browseLabel}>Browse Files</label>
            </div>
          ) : null}

          {isSyncing && (
            <div className={styles.syncProgressContainer}>
              <div className={styles.syncStatusText}>{syncStatus}</div>
              <div className={styles.syncProgressTrack}>
                <div className={styles.syncProgressBar} style={{ width: `${syncProgress}%` }} />
              </div>
            </div>
          )}
        </div>

        <div className={styles.importHeader}>
          <h3 style={{ margin: 0, fontSize: '15px', fontWeight: 600 }}>Recent Imports</h3>
        </div>

        <div className={styles.importList}>
          {recentImports.length === 0 ? (
            <p style={{ fontSize: '12px', color: 'var(--text-secondary)', textAlign: 'center', padding: '20px 0' }}>No manual imports completed yet.</p>
          ) : (
            recentImports.map((imp, idx) => (
              <div key={idx} className={styles.importItem}>
                <div className={styles.importItemInfo}>
                  <h4>{imp.name}</h4>
                  <p>{imp.count.toLocaleString()} nodes added • {imp.date} • Source: {imp.platform}</p>
                </div>
                <span className={`${styles.statusPill} ${styles.statusCompleted}`}>
                  {imp.status}
                </span>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import styles from './ActionQueue.module.css';
import { ALL_POSSIBLE_PLATFORMS } from '@/config/platforms';
import { BoltIcon } from '../common/icons/PlatformIcons';
import { createClient } from '@/utils/supabase/client';
import type { RealtimePostgresChangesPayload } from '@supabase/supabase-js';

interface ActionItem {
  id: string;
  memory_id: string | null;
  source_id?: string | null;
  platform_link?: string | null;
  platform: string;
  title: string;
  description: string;
  suggested_action: string;
  action_type: string;
  method?: 'POST' | 'PATCH' | 'DELETE';
  confidence: number;
  status: string;
  extracted_at: string;
  startTime?: string;
  endTime?: string;
}

interface RecentlyHandledItem {
  id: string;
  platform: string;
  title: string;
  status: string;
  executed_at: string | null;
  extracted_at: string;
}

interface ActionQueueViewProps {
  onBack: () => void;
}

const PLATFORM_ICONS: Record<string, string> = {
  gmail: '📧', 'google-calendar': '📅', github: '🐙',
  linear: '🔷', trello: '📋', slack: '💬', notion: '📄', discord: '🎮',
};

function useCountdown(lastRunAt: string | null, intervalMs = 30 * 60 * 1000) {
  const [remaining, setRemaining] = useState('');
  useEffect(() => {
    if (!lastRunAt) { setRemaining(''); return; }
    const tick = () => {
      const nextRun = new Date(lastRunAt).getTime() + intervalMs;
      const diff = nextRun - Date.now();
      if (diff <= 0) { setRemaining('any moment'); return; }
      const m = Math.floor(diff / 60000);
      const s = Math.floor((diff % 60000) / 1000);
      setRemaining(`${m}m ${s.toString().padStart(2, '0')}s`);
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [lastRunAt, intervalMs]);
  return remaining;
}

function getConversationalSummary(action: ActionItem) {
  const platformName = action.platform.toLowerCase() === 'gmail' ? 'an email' : `a ${action.platform} message`;
  let sender = 'Someone';

  const match = action.description?.match(/^([a-zA-Z0-9\s\-_]+)\s+asked:/i);
  if (match) {
    sender = match[1];
  } else if (action.description?.includes('asked:')) {
    sender = action.description.split('asked:')[0].trim();
  } else {
    const firstWord = action.title.split(' ')[0] || '';
    const actionVerbs = ['review', 'send', 'create', 'reply', 'submit', 'schedule', 'update', 'approve', 'dismiss', 'check', 'verify', 'vote', 'invite', 'trade', 'resolve', 'attend'];
    if (firstWord && !actionVerbs.includes(firstWord.toLowerCase())) {
      sender = firstWord;
    } else {
      sender = 'Someone';
    }
  }

  let cleanDesc = action.description || '';
  if (cleanDesc.includes('Citations:')) {
    cleanDesc = cleanDesc.split('Citations:')[0].trim();
  }
  cleanDesc = cleanDesc.replace(/^.*asked:\s*/i, '').replace(/^"|"$/g, '').trim();
  if (!cleanDesc) {
    cleanDesc = action.title;
  }

  return { sender, platformName, cleanDesc };
}

function parseCitations(desc: string) {
  const citations: string[] = [];
  const lines = desc.split('\n');
  let inCitations = false;
  for (const line of lines) {
    if (line.toLowerCase().includes('citations:')) {
      inCitations = true;
      continue;
    }
    if (inCitations && line.trim().startsWith('-')) {
      citations.push(line.trim().slice(1).trim());
    }
  }
  return citations;
}

function getNativePlatformLink(action: ActionItem) {
  if (action.platform_link) return action.platform_link;

  const platform = action.platform.toLowerCase();
  const sourceId = action.source_id;

  if (platform === 'gmail') {
    if (sourceId) {
      return `https://mail.google.com/mail/u/0/#all/${sourceId}`;
    }
    return `https://mail.google.com/mail/u/0/#search/${encodeURIComponent(action.title)}`;
  }

  if (platform === 'slack') {
    if (sourceId && !sourceId.startsWith('test_')) {
      return `https://slack.com/app_redirect?channel=${sourceId}`;
    }
    return 'https://slack.com';
  }

  if (platform === 'github') {
    if (sourceId) return `https://github.com/${sourceId}`;
    return 'https://github.com';
  }

  if (platform === 'linear') {
    if (sourceId) return `https://linear.app/issue/${sourceId}`;
    return 'https://linear.app';
  }

  return null;
}

export function ActionQueueView({ onBack }: ActionQueueViewProps) {
  const [actions, setActions] = useState<ActionItem[]>([]);
  const [recentlyHandled, setRecentlyHandled] = useState<RecentlyHandledItem[]>([]);
  const [scanStats, setScanStats] = useState<Record<string, number>>({});
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<'all' | 'priority' | 'meetings' | 'communications' | 'tasks'>('all');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editedAction, setEditedAction] = useState<ActionItem | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [lastRunAt, setLastRunAt] = useState<string | null>(null);
  const [refiningId, setRefiningId] = useState<string | null>(null);
  // undoToast: holds the dismissed item + its removal timer so Undo can cancel it
  const [undoToast, setUndoToast] = useState<{ action: ActionItem; timerId: ReturnType<typeof setTimeout> } | null>(null);
  const countdown = useCountdown(lastRunAt);

  // ── Step 1: Load instantly from DB ───────────────────────────────────────────
  const loadFromDB = useCallback(async () => {
    try {
      const res = await fetch('/api/actions/queue', { method: 'GET' });
      if (res.status === 401) {
        window.location.href = '/login';
        return;
      }
      if (!res.ok) throw new Error(`Queue load error: ${res.status}`);
      const data = await res.json();

      setActions(data.actions ?? []);
      setLastRunAt(data.meta?.lastRunAt ?? null);
      setScanStats(data.meta?.scanStats ?? {});
      setRecentlyHandled(data.recentlyHandled ?? []);

      // ── Step 2: If stale, trigger background extraction (non-blocking) ─────
      if (data.meta?.isStale) {
        console.log('[ActionQueue] Stale — triggering background extraction...');
        triggerBackgroundExtraction();
      }
    } catch (e) {
      console.error('[ActionQueue] Load failed:', e);
    } finally {
      setLoading(false);
    }
  }, []);

  // Trigger extraction in background — UI doesn't wait for this
  const triggerBackgroundExtraction = async () => {
    setRefreshing(true);
    try {
      await fetch('/api/actions/extract', { method: 'POST' });
      // Real-time subscription will push new actions — no need to re-fetch
    } catch (e) {
      console.warn('[ActionQueue] Background extraction failed:', e);
    } finally {
      setRefreshing(false);
    }
  };

  // Manual re-scan button
  const handleRescan = async () => {
    setRefreshing(true);
    try {
      await fetch('/api/actions/extract', { method: 'POST' });
    } catch (e) {
      console.warn('[ActionQueue] Re-scan failed:', e);
    } finally {
      setRefreshing(false);
    }
  };

  useEffect(() => {
    loadFromDB();
    if (typeof window !== 'undefined') {
      const params = new URLSearchParams(window.location.search);
      const actionId = params.get('id');
      if (actionId) {
        setExpandedId(actionId);
      }
    }
  }, [loadFromDB]);

  useEffect(() => {
    if (expandedId && actions.length > 0) {
      setTimeout(() => {
        const el = document.getElementById(expandedId);
        if (el) {
          el.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 300);
    }
  }, [expandedId, actions]);

  // ── Step 3: Real-time subscription — replaces 30s polling ────────────────────
  useEffect(() => {
    const supabase = createClient();

    const channel = supabase
      .channel('action_queue_realtime')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'action_queue' },
        (payload: RealtimePostgresChangesPayload<Record<string, unknown>>) => {
          if (payload.eventType === 'INSERT') {
            const newAction = payload.new as unknown as ActionItem;
            if (newAction.status === 'pending') {
              setActions(prev => {
                if (prev.find(a => a.id === newAction.id)) return prev;
                return [newAction, ...prev];
              });
            }
          } else if (payload.eventType === 'UPDATE') {
            const updated = payload.new as unknown as ActionItem;
            if (updated.status !== 'pending') {
              // Remove from UI if no longer pending
              setActions(prev => prev.filter(a => a.id !== updated.id));
            } else {
              setActions(prev => prev.map(a => a.id === updated.id ? updated : a));
            }
          } else if (payload.eventType === 'DELETE') {
            setActions(prev => prev.filter(a => a.id !== (payload.old as unknown as ActionItem).id));
          }
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  // ── Action handlers ──────────────────────────────────────────────────────────

  // Single atomic call: approved → execute → executed|failed
  const handleApprove = async (action: ActionItem) => {
    // C5 fix: explicit null guard — editedAction || action would silently discard
    // user edits if editedAction happened to be null due to a state race.
    const finalAction = (editingId === action.id && editedAction != null)
      ? editedAction
      : action;
    setProcessingId(action.id);
    try {
      const res = await fetch('/api/actions/approve', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          id: finalAction.id,
          title: finalAction.title,
          suggested_action: finalAction.suggested_action,
          startTime: finalAction.startTime,
          endTime: finalAction.endTime,
        }),
      });
      const data = await res.json();
      if (!res.ok) {
        console.error('[ActionQueue] Approve failed:', data.error);
      }
      // Realtime subscription will remove the card; do it optimistically too
      setActions(prev => prev.filter(a => a.id !== action.id));
      setEditingId(null);
      setEditedAction(null);
    } catch (e) {
      console.error('[ActionQueue] Approve network error:', e);
    } finally {
      setProcessingId(null);
    }
  };

  // Dismiss with 3-second undo window before committing to DB
  const handleDismiss = (action: ActionItem) => {
    if (editingId === action.id) { setEditingId(null); setEditedAction(null); }

    // Cancel any previous pending toast first
    if (undoToast) {
      clearTimeout(undoToast.timerId);
      // Commit the previous one immediately before showing new toast
      fetch('/api/actions/queue', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id: undoToast.action.id, status: 'dismissed' }),
      }).catch(e => console.warn('[ActionQueue] Dismiss persist failed:', e));
    }

    // Optimistically remove from list
    setActions(prev => prev.filter(a => a.id !== action.id));

    // Schedule DB write after 3 seconds (cancellable)
    const timerId = setTimeout(() => {
      fetch('/api/actions/queue', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id: action.id, status: 'dismissed' }),
      }).catch(e => console.warn('[ActionQueue] Dismiss persist failed:', e));
      setUndoToast(null);
    }, 3000);

    setUndoToast({ action, timerId });
  };

  const handleUndoDismiss = () => {
    if (!undoToast) return;
    clearTimeout(undoToast.timerId);
    // Restore the action to the top of the list
    setActions(prev => [undoToast.action, ...prev]);
    setUndoToast(null);
  };

  const startEditing = (action: ActionItem) => {
    setEditingId(action.id);
    setEditedAction({ ...action });
  };

  const handleEditChange = (action: ActionItem, field: keyof ActionItem, value: string) => {
    if (editingId !== action.id) {
      setEditingId(action.id);
      setEditedAction({ ...action, [field]: value });
    } else if (editedAction) {
      setEditedAction({ ...editedAction, [field]: value });
    }
  };

  const applyQuickRefine = async (action: ActionItem, type: 'shorter' | 'formal' | 'calendar') => {
    const currentText = editingId === action.id ? editedAction?.suggested_action || action.suggested_action : action.suggested_action;

    // Enter edit mode immediately with the current text so user sees the field
    if (editingId !== action.id) {
      setEditingId(action.id);
      setEditedAction({ ...action });
    }
    setRefiningId(action.id);

    try {
      const res = await fetch('/api/actions/refine', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text: currentText, type }),
      });
      const data = await res.json();
      if (res.ok && data.refined) {
        setEditedAction(prev => prev ? { ...prev, suggested_action: data.refined } : { ...action, suggested_action: data.refined });
      }
    } catch (e) {
      console.warn('[ActionQueue] Refine failed:', e);
    } finally {
      setRefiningId(null);
    }
  };

  const filtered = actions.filter(a => {
    if (activeFilter === 'priority') return a.confidence >= 80;
    if (activeFilter === 'meetings') return a.action_type === 'CALENDAR';
    if (activeFilter === 'communications') return ['gmail', 'slack', 'discord'].includes(a.platform.toLowerCase());
    if (activeFilter === 'tasks') return ['github', 'linear', 'trello'].includes(a.platform.toLowerCase());
    return true;
  });

  const lastRunDisplay = lastRunAt
    ? `Last scan: ${new Date(lastRunAt).toLocaleTimeString()}`
    : 'Never scanned';

  return (
    <div className={styles.queueRoot}>
      <header className={styles.queueHeader}>
        <div className={styles.headerTitleGroup}>
          <h1 className={styles.mainTitle}>Action Command Bridge</h1>
          <p className={styles.subtitle}>
            Review and approve actions discovered across your connected sources.
            {' '}<span style={{ opacity: 0.5, fontSize: '0.75rem' }}>{lastRunDisplay}</span>
          </p>
        </div>
        <button
          className={styles.refreshBtn}
          onClick={handleRescan}
          disabled={refreshing}
          style={{ alignSelf: 'flex-start' }}
