                            })()}

                            {/* AI Suggestion Box */}
                            <div className={styles.suggestionBox}>
                              <span className={styles.suggestionLabel}>
                                {action.action_type === 'EMAIL_REPLY' || action.action_type === 'SLACK_REPLY' ? 'AI DRAFT REPLY' : 'PROPOSED COMMAND'}
                              </span>
                              {isEditing ? (
