                                {refiningId === action.id && (
                                  <span style={{ fontSize: '0.72rem', color: 'var(--text-muted)', letterSpacing: '0.05em' }}>✦ refining…</span>
                                )}
                                {refiningId !== action.id && (
                                  <>
                                    <button
                                      onClick={(e) => { e.stopPropagation(); applyQuickRefine(action, 'shorter'); }}
