                                      style={{ background: 'var(--bg-secondary)', border: '1px solid var(--border-subtle)', borderRadius: '16px', padding: '6px 14px', fontSize: '0.75rem', color: 'var(--text-primary)', fontWeight: '700', cursor: 'pointer' }}
