                            AUTO-APPROVE
                          </button>
                        )}
                        {!isEditing && (
                          <button className={styles.editBtn} onClick={(e) => { e.stopPropagation(); startEditing(action); }}>REFINE</button>
                        )}
                        {!isEditing && (() => {
                          const link = getNativePlatformLink(action);
                          if (!link) return null;
                          return (
                            <a 
                              href={link} 
