                  {/* Main Grid showing Dynamic Card Curation */}
                  <div className={styles.sanctumMain}>
                    <div className={styles.sanctumGrid}>
                      <AnimatePresence mode="popLayout">
                        {filteredCards.slice(0, 6).map((card) => (
