'use client';

import { useState, useEffect, useMemo } from 'react';
import { useRouter, useSearchParams, usePathname } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import {
  ConnectorsIcon,
  PlusIcon,
  AIIntegrationIcon,
  AuditIcon,
  GraphIcon,
  FeedIcon,
  ActionIcon
} from '../common/icons/SidebarIcons';
import styles from './Sidebar.module.css';
import EyesLogo from '../common/EyesLogo';

interface Platform {
  id: string;
  connected: boolean;
  status: string;
}

export default function Sidebar() {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const activeView = searchParams.get('view') || 'dashboard';
  const activeThreadId = searchParams.get('threadId');
  const [platforms, setPlatforms] = useState<Platform[]>([]);
  const [threads, setThreads] = useState<any[]>([]);
  const [starredIds, setStarredIds] = useState<string[]>([]);
  const [editingThreadId, setEditingThreadId] = useState<string | null>(null);
  const [editThreadTitle, setEditThreadTitle] = useState('');
  const { user } = useAuth();

  const adminEmailsEnv = process.env.NEXT_PUBLIC_ADMIN_EMAILS || '';
  const adminEmails = adminEmailsEnv.split(',')
    .map(email => email.trim().toLowerCase())
    .filter(email => email !== '');
  const isAdmin = user && user.email && adminEmails.length > 0 && adminEmails.includes(user.email.toLowerCase());

  // Load readiness status
  useEffect(() => {
    const loadReadiness = async () => {
      try {
        const response = await fetch('/api/platform-readiness', { cache: 'no-store' });
        if (response.ok) {
          const data = await response.json();
          setPlatforms(data.platforms || []);
        }
      } catch (e) { }
    };
    loadReadiness();
    const interval = setInterval(loadReadiness, 120000); // Every 2 min
    return () => clearInterval(interval);
  }, []);

  // Fetch threads — simple and reliable, no auto-deletion
  const fetchThreads = async () => {
    try {
      const res = await fetch('/api/chat/threads');
      if (res.ok) {
        const data = await res.json();
        const allThreads: any[] = data.threads || [];
        // Only show threads that have at least 1 saved message
        setThreads(allThreads.filter(t => (t.chat_messages?.length ?? 0) > 0));
      }
    } catch (e) {
      console.error('[Sidebar] Failed to load threads:', e);
    }
  };

  // Load threads on mount + poll every 8 seconds (like ChatGPT — current convo appears in real-time)
  useEffect(() => {
    if (typeof window !== 'undefined') {
      try {
        const raw = localStorage.getItem('eyes_starred_threads');
        // eslint-disable-next-line react-hooks/set-state-in-effect
        if (raw) setStarredIds(JSON.parse(raw));
      } catch (e) {
        console.error(e);
      }
    }
    fetchThreads();
    const pollInterval = setInterval(fetchThreads, 8000);

    // Also listen for explicit save events for immediate update
    const handleSaved = () => fetchThreads();
    window.addEventListener('eyes-chat-saved', handleSaved);
    window.addEventListener('eyes-realtime-refresh', handleSaved);
    return () => {
      clearInterval(pollInterval);
      window.removeEventListener('eyes-chat-saved', handleSaved);
      window.removeEventListener('eyes-realtime-refresh', handleSaved);
    };
  }, []);

  const toggleStar = (threadId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setStarredIds((prev) => {
      const next = prev.includes(threadId)
        ? prev.filter(id => id !== threadId)
        : [...prev, threadId];
      if (typeof window !== 'undefined') {
        localStorage.setItem('eyes_starred_threads', JSON.stringify(next));
      }
      return next;
    });
  };

  const handleDeleteThread = async (threadId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!window.confirm('Delete this conversation?')) return;
    try {
      const res = await fetch(`/api/chat/threads?threadId=${threadId}`, { method: 'DELETE' });
      if (res.ok) {
        setThreads(prev => prev.filter(t => t.id !== threadId));
        setStarredIds(prev => {
          const next = prev.filter(id => id !== threadId);
          localStorage.setItem('eyes_starred_threads', JSON.stringify(next));
          return next;
        });
        if (searchParams.get('threadId') === threadId) {
          router.push('/?view=dashboard&new=' + Date.now());
        }
        window.dispatchEvent(new CustomEvent('eyes-chat-saved'));
      }
    } catch (err) {
      console.error('Failed to delete thread:', err);
    }
  };

  const handleEditSubmit = async (threadId: string) => {
    if (!editThreadTitle.trim()) {
      setEditingThreadId(null);
      return;
    }

    try {
      const res = await fetch('/api/chat/threads', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ threadId, title: editThreadTitle.trim() })
      });
      if (res.ok) {
        setThreads(prev => prev.map(t => t.id === threadId ? { ...t, title: editThreadTitle.trim() } : t));
      }
    } catch (e) {
      console.error('Failed to update thread title:', e);
    }
    setEditingThreadId(null);
  };

  // Group threads chronologically
  const groupedThreads = useMemo(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);

    const sevenDaysAgo = new Date(today);
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

    const starred: any[] = [];
    const todayGroup: any[] = [];
    const yesterdayGroup: any[] = [];
    const last7DaysGroup: any[] = [];
    const olderGroup: any[] = [];

    threads.forEach(t => {
      if (starredIds.includes(t.id)) {
        starred.push(t);
        return;
      }

      const date = new Date(t.updated_at || t.created_at);
      date.setHours(0, 0, 0, 0);

      if (date.getTime() === today.getTime()) {
        todayGroup.push(t);
      } else if (date.getTime() === yesterday.getTime()) {
        yesterdayGroup.push(t);
      } else if (date.getTime() >= sevenDaysAgo.getTime()) {
        last7DaysGroup.push(t);
      } else {
        olderGroup.push(t);
      }
    });

    return {
      starred,
      today: todayGroup,
      yesterday: yesterdayGroup,
      last7Days: last7DaysGroup,
      older: olderGroup
    };
  }, [threads, starredIds]);

  const connectedCount = platforms.filter(p => p.connected).length;
  const coverageScore = useMemo(() => {
    if (platforms.length === 0) return 0;
    return Math.round((connectedCount / platforms.length) * 100);
  }, [platforms, connectedCount]);

  const circumference = 2 * Math.PI * 45;
  const offset = circumference - (coverageScore / 100) * circumference;

  const navigateToView = (view: string) => {
    if (view === 'chat') {
      if (pathname === '/chat') {
        router.push(`/chat?new=${Date.now()}`);
      } else {
        router.push(`/?view=dashboard&new=${Date.now()}`);
      }
    } else if (view === 'dashboard') {
      router.push('/');
    } else if (view === 'admin-funnel') {
      router.push('/admin/funnel');
    } else {
      router.push(`/?view=${view}`);
    }
  };

  const renderThreadItem = (t: any) => {
    const isActive = activeThreadId === t.id;
    const isStarred = starredIds.includes(t.id);
    const targetUrl = pathname === '/chat'
      ? `/chat?threadId=${t.id}`
      : `/?view=dashboard&threadId=${t.id}`;

    return (
      <div
        key={t.id}
        className={`${styles.chatItem} ${isActive ? styles.chatItemActive : ''} ${isStarred ? styles.chatItemStarred : ''}`}
        onClick={() => {
          if (editingThreadId !== t.id) {
            router.push(targetUrl);
          }
        }}
      >
        {editingThreadId === t.id ? (
          <input
            type="text"
            value={editThreadTitle}
            onChange={(e) => setEditThreadTitle(e.target.value)}
            onBlur={() => handleEditSubmit(t.id)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') handleEditSubmit(t.id);
              if (e.key === 'Escape') setEditingThreadId(null);
            }}
            className={styles.chatTitleInput}
            autoFocus
            onClick={(e) => e.stopPropagation()}
          />
        ) : (
          <span className={styles.chatTitle}>{t.title}</span>
        )}
        <div className={styles.chatActions}>
          <button
            className={`${styles.chatActionBtn} ${isStarred ? styles.starBtnActive : ''}`}
            onClick={(e) => toggleStar(t.id, e)}
            title={isStarred ? "Unstar" : "Star"}
          >
            ★
          </button>
          <button
            className={styles.chatActionBtn}
            onClick={(e) => {
              e.stopPropagation();
              setEditingThreadId(t.id);
              setEditThreadTitle(t.title);
            }}
            title="Rename chat"
          >
            ✎
          </button>
          <button
            className={styles.chatActionBtn}
            onClick={(e) => handleDeleteThread(t.id, e)}
            title="Delete chat"
          >
            ✕
          </button>
        </div>
      </div>
    );
  };

  return (
    <aside className={styles.sidebar}>
      <div onClick={() => router.push('/')} style={{ cursor: 'pointer', display: 'flex', alignItems: 'center', padding: '6px 12px', marginBottom: '16px', color: 'var(--text-primary)' }}>
        <EyesLogo width={92} height={22} />
      </div>

      <button className={styles.newChatBtn} onClick={async () => {
        // Refresh sidebar first so current conversation appears as history
        await fetchThreads();
        navigateToView('chat');
      }}>
        <PlusIcon /> New chat
      </button>

      <div className={styles.scrollArea}>
        <div className={styles.section}>
          <div
            className={`${styles.item} ${activeView === 'connectors' ? styles.itemActive : ''}`}
            onClick={() => navigateToView('connectors')}
          >
            <div className={styles.itemIcon}><ConnectorsIcon /></div>
            <div className={styles.itemMain}>
              <span className={styles.itemLabel}>Connectors</span>
              <span className={styles.itemDesc}>Manage connected sources</span>
            </div>
          </div>

          <div
            className={`${styles.item} ${activeView === 'feed' ? styles.itemActive : ''}`}
            onClick={() => navigateToView('feed')}
          >
            <div className={styles.itemIcon}><FeedIcon /></div>
            <div className={styles.itemMain}>
              <span className={styles.itemLabel}>Source Feed</span>
              <span className={styles.itemDesc}>Ingested raw memories</span>
            </div>
          </div>

          <div
            className={`${styles.item} ${activeView === 'timeline' ? styles.itemActive : ''}`}
            onClick={() => navigateToView('timeline')}
          >
            <div className={styles.itemIcon}><GraphIcon /></div>
            <div className={styles.itemMain}>
              <span className={styles.itemLabel}>Time Line</span>
              <span className={styles.itemDesc}>Chronological event mapping</span>
            </div>
          </div>

          <div
            className={`${styles.item} ${activeView === 'audit' ? styles.itemActive : ''}`}
            onClick={() => navigateToView('audit')}
          >
            <div className={styles.itemIcon}><AuditIcon /></div>
            <div className={styles.itemMain}>
              <span className={styles.itemLabel}>Audit</span>
              <span className={styles.itemDesc}>Consistency & contradiction report</span>
            </div>
          </div>

          <div
            className={`${styles.item} ${activeView === 'action-queue' ? styles.itemActive : ''}`}
            onClick={() => navigateToView('action-queue')}
          >
            <div className={styles.itemIcon}><ActionIcon /></div>
            <div className={styles.itemMain}>
              <span className={styles.itemLabel}>Action Queue <span style={{ fontSize: '8px', background: 'var(--accent-primary)', color: 'var(--bg-primary)', padding: '2px 4px', borderRadius: '4px', marginLeft: '4px', fontWeight: 800 }}>BETA</span></span>
              <span className={styles.itemDesc}>Review and approve actions</span>
            </div>
          </div>




          {isAdmin && (
            <div
              className={`${styles.item} ${activeView === 'admin-funnel' ? styles.itemActive : ''}`}
              onClick={() => navigateToView('admin-funnel')}
              style={{ borderLeft: '2px solid #E06A3B', paddingLeft: '6px' }}
            >
              <div className={styles.itemIcon}><GraphIcon /></div>
              <div className={styles.itemMain}>
                <span className={styles.itemLabel} style={{ color: '#E06A3B' }}>Admin Analytics</span>
                <span className={styles.itemDesc}>Onboarding funnel metrics</span>
              </div>
            </div>
          )}

          <div className={styles.chatHistoryContainer}>
            <div className={styles.chatHistoryDivider} />

            {/* Starred Group */}
            {groupedThreads.starred.length > 0 && (
              <div>
                <div className={styles.historyHeader}>Starred</div>
                {groupedThreads.starred.map(renderThreadItem)}
              </div>
            )}

            {/* Today Group */}
            {groupedThreads.today.length > 0 && (
              <div>
                <div className={styles.historyHeader}>Today</div>
                {groupedThreads.today.map(renderThreadItem)}
              </div>
            )}

            {/* Yesterday Group */}
            {groupedThreads.yesterday.length > 0 && (
              <div>
                <div className={styles.historyHeader}>Yesterday</div>
                {groupedThreads.yesterday.map(renderThreadItem)}
              </div>
            )}

            {/* Last 7 Days Group */}
            {groupedThreads.last7Days.length > 0 && (
              <div>
                <div className={styles.historyHeader}>Previous 7 Days</div>
                {groupedThreads.last7Days.map(renderThreadItem)}
              </div>
            )}

            {/* Older Group */}
            {groupedThreads.older.length > 0 && (
              <div>
                <div className={styles.historyHeader}>Older</div>
                {groupedThreads.older.map(renderThreadItem)}
              </div>
            )}
          </div>
        </div>
      </div>

      <div className={styles.footer}>
        <div className={styles.readinessCard} onClick={() => navigateToView('readiness')}>
          <div className={styles.readinessHeader}>
            <span className={styles.readinessTitle}>SOURCE READINESS</span>
          </div>

          <div className={styles.readinessContent}>
            <div className={styles.gaugeWrapper}>
              <svg viewBox="0 0 100 100" className={styles.gaugeSvg}>
                <circle cx="50" cy="50" r="45" className={styles.gaugeBg} />
                <circle
                  cx="50" cy="50" r="45"
                  className={styles.gaugeFill}
                  strokeDasharray={circumference}
                  strokeDashoffset={offset}
                  style={{ transition: 'stroke-dashoffset 0.8s ease' }}
                />
                <text x="50" y="58" textAnchor="middle" className={styles.gaugeText}>{coverageScore}%</text>
              </svg>
            </div>
            <div className={styles.readinessInfo}>
              <div className={styles.platformsCount}>
                {connectedCount}/{platforms.length} Platforms
              </div>
              <div className={styles.reliabilityLabel}>
                Reliability: <span className={styles.reliabilityHigh}>High</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </aside>
  );
}

'use client';

import { createContext, useContext, useState, useEffect, useCallback, useMemo, useRef, type ReactNode } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import { createClient } from '@/utils/supabase/client';
import styles from './AuthContext.module.css';
import {
  useAuthSession,
  resetPulseTimer,
  getErrorMessage,
  purgeSupabaseLocalAuthArtifacts,
  isRefreshTokenFailure,
} from './hooks/useAuthSession';
import { useRealtimeSync } from './hooks/useRealtimeSync';
import { useBackgroundSync } from './hooks/useBackgroundSync';

export interface User {
  id: string;
  name: string;
  email: string;
  avatar: string;
  plan: string;
  joinedDate: string;
  memoriesIndexed: number;
  behaviorLoggingConsent: boolean;
  onboardingCompleted: boolean;
}

export type AuthResult = {
  success: boolean;
  message?: string;
};

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  login: (email: string, password: string) => Promise<AuthResult>;
  signup: (name: string, email: string, password: string) => Promise<AuthResult>;
  loginWithGoogle: () => Promise<AuthResult>;
  loginWithGithub: () => Promise<AuthResult>;
  loginWithDiscord: () => Promise<AuthResult>;
  logout: () => Promise<void>;
  resetPassword: (email: string) => Promise<AuthResult>;
  supabase: ReturnType<typeof createClient>;
  updateUser: (updates: Partial<User>) => Promise<AuthResult>;
  theme: 'dark' | 'light' | 'ember';
  setGlobalTheme: (theme: 'dark' | 'light' | 'ember') => void;
}

type AuthMetadata = {
  name?: string;
};

type UserProfileRow = {
  name: string;
  avatar: string | null;
  plan: string | null;
  joined_date: string | null;
  memories_indexed: number | null;
  behavior_logging_consent: boolean | null;
  onboarding_completed: boolean | null;
};

type DBResult<T> = {
  data: T | null;
  error: { message?: string } | null;
};

// Legacy aliases kept for backward compat with existing call sites
type QueryResult<T> = DBResult<T>;
type SupabaseQueryLike<T> = DBResult<T>;

const PROFILE_CACHE_KEY = 'eyes-user-profile-v1';

// Timeout wrapper for supabase calls — prevents infinite hangs
async function quickFetch<T>(
  promise: PromiseLike<T> | Promise<T>,
  timeoutMs: number,
  fallback: T
): Promise<T> {
  type S = { state: 'resolved'; value: T } | { state: 'rejected'; error: unknown } | { state: 'timed_out' };
  let tid: ReturnType<typeof setTimeout> | undefined;
  const wrapped = Promise.resolve(promise)
    .then<S>(value => ({ state: 'resolved', value }))
    .catch<S>((error: unknown) => ({ state: 'rejected', error }));
  const timeout = new Promise<S>(resolve => {
    tid = setTimeout(() => resolve({ state: 'timed_out' }), timeoutMs);
  });
  const result = await Promise.race([wrapped, timeout]);
  if (tid !== undefined) clearTimeout(tid);
  if (result.state === 'timed_out') return fallback;
  if (result.state === 'rejected') throw result.error;
  return result.value;
}

function loadCachedProfile(): User | null {
  if (typeof window === 'undefined') return null;
  try {
    const raw = localStorage.getItem(PROFILE_CACHE_KEY);
    return raw ? (JSON.parse(raw) as User) : null;
  } catch {
    return null;
  }
}

function saveCachedProfile(profile: User): void {
  if (typeof window === 'undefined') return;
  try {
    localStorage.setItem(PROFILE_CACHE_KEY, JSON.stringify(profile));
  } catch { /* quota full — not critical */ }
}

function clearCachedProfile(): void {
  if (typeof window === 'undefined') return;
  localStorage.removeItem(PROFILE_CACHE_KEY);
}

const AuthContext = createContext<AuthContextType | null>(null);

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}
const PUBLIC_ROUTES = [
  '/',
  '/login',
  '/signup',
  '/privacy-policy',
  '/cookie-policy',
  '/security-policy',
  '/disclaimer',
  '/accessibility',
  '/terms',
  '/california-notice'
];

const GUEST_ONLY_ROUTES = ['/login', '/signup'];
const ONBOARDING_ROUTE = '/onboarding';

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<'dark' | 'light' | 'ember'>('dark');
  const [showAuthFallback, setShowAuthFallback] = useState(false);
  const router = useRouter();
  const pathname = usePathname();

  const supabase = useMemo(() => createClient(), []);

  const syncInProgressRef = useRef(false);

  const syncProfile = useCallback(async (authUser: { id: string; email?: string; metadata?: AuthMetadata }): Promise<User> => {
    if (syncInProgressRef.current) {
      console.log('[Auth] Profile sync already in progress, skipping duplicate call.');
      // Return a temporary user while the first call finishes
      return {
        id: authUser.id,
        name: authUser.metadata?.name || authUser.email?.split('@')[0] || 'User',
        email: authUser.email || '',
        avatar: (authUser.metadata?.name || authUser.email?.split('@')[0] || 'U').charAt(0).toUpperCase(),
        plan: loadCachedProfile()?.plan || 'Private Beta',   // M1: use cached plan while sync completes
        joinedDate: new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'short' }),
        memoriesIndexed: 0,
        behaviorLoggingConsent: loadCachedProfile()?.behaviorLoggingConsent ?? true,
        onboardingCompleted: loadCachedProfile()?.onboardingCompleted ?? false,
      };
    }

    syncInProgressRef.current = true;
    console.log('[Auth] Syncing profile for:', authUser.id);
    const fallbackName = authUser.metadata?.name || authUser.email?.split('@')[0] || 'User';
    const initials = fallbackName.charAt(0).toUpperCase();
    const joinedDate = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'short' });

    // ── Fast path: return cached profile immediately, refresh in background ──
    const cached = loadCachedProfile();
    if (cached && cached.id === authUser.id) {
      syncInProgressRef.current = false;
      // Refresh in background silently — no await, no blocking
      void (async () => {
        try {
          const fetchResult = await quickFetch<QueryResult<UserProfileRow>>(
            supabase
              .from('user_profiles')
              .select('name,avatar,plan,joined_date,memories_indexed,behavior_logging_consent,onboarding_completed')
              .eq('user_id', authUser.id)
              .maybeSingle()
              .then((result: SupabaseQueryLike<UserProfileRow>) => ({ data: result.data, error: result.error })),
            5000,
            { data: null, error: { message: 'Timed out' } }
          );
          if (fetchResult.data) {
            const fresh: User = {
              id: authUser.id,
              name: fetchResult.data.name,
              email: authUser.email || '',
              avatar: fetchResult.data.avatar || initials,
              plan: fetchResult.data.plan || 'Private Beta',
              joinedDate: fetchResult.data.joined_date || joinedDate,
              memoriesIndexed: fetchResult.data.memories_indexed || 0,
              behaviorLoggingConsent: fetchResult.data.behavior_logging_consent ?? true,
              onboardingCompleted: fetchResult.data.onboarding_completed ?? false,
            };
            saveCachedProfile(fresh);
            setUser(fresh); // M2: update live UI with fresh data (was only updating cache)
          }
        } catch { /* background refresh failed — cache still valid */ }
      })();
      return cached;
    }

    try {
      // Increase timeout to 8s to handle DB load during syncs.
      const fetchResult = await quickFetch<QueryResult<UserProfileRow>>(
        supabase
          .from('user_profiles')
          .select('name,avatar,plan,joined_date,memories_indexed,behavior_logging_consent,onboarding_completed')
          .eq('user_id', authUser.id)
          .maybeSingle()
          .then((result: SupabaseQueryLike<UserProfileRow>) => ({ data: result.data, error: result.error })),
        8000,  // L2: comment said 15s but was actually 5s — now 8s
        { data: null, error: { message: 'Timed out' } }
      );

      const profile = fetchResult.data;
      const isTimeout = fetchResult.error?.message === 'Timed out';

      if (profile) {
        syncInProgressRef.current = false;
        const result: User = {
          id: authUser.id,
          name: profile.name,
          email: authUser.email || '',
          avatar: profile.avatar || initials,
          plan: profile.plan || 'Private Beta',   // ← read from DB, fallback only if null
          joinedDate: profile.joined_date || joinedDate,
          memoriesIndexed: profile.memories_indexed || 0,
          behaviorLoggingConsent: profile.behavior_logging_consent ?? true,
          onboardingCompleted: profile.onboarding_completed ?? false,
        };
        saveCachedProfile(result); // ← persist for instant load next time
        return result;
      }

      // ONLY create if it's definitely missing, NOT on timeouts
      if (isTimeout) {
        console.warn('[Auth] Profile fetch timed out. Using fallback user to avoid loop.');
        syncInProgressRef.current = false;
        // Use cached plan if available, otherwise default
        const cached = loadCachedProfile();
        return {
          id: authUser.id,
          name: fallbackName,
          email: authUser.email || '',
          avatar: initials,
          plan: cached?.plan || 'Private Beta',
          joinedDate: joinedDate,
          memoriesIndexed: cached?.memoriesIndexed || 0,
          behaviorLoggingConsent: cached?.behaviorLoggingConsent ?? true,
          onboardingCompleted: cached?.onboardingCompleted ?? false,
        };
      }

      // Create profile if missing
      console.log('[Auth] Profile confirmed missing, creating new record.');
      const newProfile = {
        user_id: authUser.id,
        name: fallbackName,
        avatar: initials,
        plan: 'Private Beta',
        joined_date: joinedDate,
        memories_indexed: 0,
        behavior_logging_consent: true,
        onboarding_completed: false,
      };

      const { data: inserted } = await quickFetch<QueryResult<UserProfileRow>>(
        supabase
          .from('user_profiles')
          .upsert(newProfile, { onConflict: 'user_id' })
          .select('name,avatar,plan,joined_date,memories_indexed,behavior_logging_consent,onboarding_completed')
          .maybeSingle()
          .then((result: SupabaseQueryLike<UserProfileRow>) => ({ data: result.data, error: result.error })),
        5000,
        { data: null, error: null }
      );

      syncInProgressRef.current = false;
      const final = inserted || newProfile;
      return {
        id: authUser.id,
        name: final.name,
        email: authUser.email || '',
        avatar: final.avatar || initials,
        plan: final.plan || 'Private Beta',   // ← read from DB even on new profile creation
        joinedDate: joinedDate,
        memoriesIndexed: 0,
        behaviorLoggingConsent: final.behavior_logging_consent ?? true,
        onboardingCompleted: final.onboarding_completed ?? false,
      };
    } catch (err) {
      syncInProgressRef.current = false;
      console.error('[Auth] Profile sync error:', err);
      // Return a valid fallback user so the app can continue
      return {
        id: authUser.id,
        name: fallbackName,
        email: authUser.email || '',
        avatar: initials,
        plan: 'Private Beta',
        joinedDate: joinedDate,
        memoriesIndexed: 0,
        behaviorLoggingConsent: true,
        onboardingCompleted: false,
      };
    }
  }, [supabase]);

  // ── useAuthSession handles session init + rejection guard ───────────────────
  useAuthSession(supabase, syncProfile, setUser, setIsLoading);
  
  // Realtime & Background Sync Hooks
  useRealtimeSync(supabase, user, isLoading, pathname);
  useBackgroundSync(supabase, user, isLoading, pathname);

  // Theme init — sole purpose of this effect after hook extraction
  useEffect(() => {
    let mounted = true;
    const savedTheme = localStorage.getItem('eyes-theme') as 'dark' | 'light' | 'ember';
    if (savedTheme && mounted) {
      setTheme(savedTheme);
      document.documentElement.setAttribute('data-theme', savedTheme);
    }
    return () => { mounted = false; };
  }, []);

  // Avoid flashing a full-screen loader for fast auth checks.
  useEffect(() => {
    if (!isLoading) {
      setShowAuthFallback(false);
      return;
    }

    const timer = setTimeout(() => {
      setShowAuthFallback(true);
    }, 350);

    return () => clearTimeout(timer);
  }, [isLoading]);

  // Routing & Session Persistence Logic
  useEffect(() => {
    if (isLoading) return;

    const isPublic = PUBLIC_ROUTES.includes(pathname);
    const isOAuthCallback = pathname.includes('/connect') || pathname.startsWith('/auth'); // M8: /auth/callback was missing
    const justSuccess =
      typeof window !== 'undefined' &&
      new URLSearchParams(window.location.search).get('oauth') === 'success';

    let redirectTimer: ReturnType<typeof setTimeout> | undefined;

    if (!user) {
      if (isPublic) return;

      // AUTH ERROR DETECTION: If the URL contains an error from Supabase/Google,
      // redirect to login immediately with the error message.
      const searchParams = new URLSearchParams(typeof window !== 'undefined' ? window.location.search : '');
      const hashParams = new URLSearchParams(typeof window !== 'undefined' ? window.location.hash.substring(1) : '');
      const errorMsg = searchParams.get('error_description') || hashParams.get('error_description') || searchParams.get('error') || hashParams.get('error');

      if (errorMsg) {
        console.error('[Auth] OAuth Error Detected:', errorMsg);
        router.replace(`/login?error=${encodeURIComponent(errorMsg)}`);
        return;
      }

      // OAUTH DAMPENER: If we just landed from an OAuth provider or a connection flow,
      // be extremely patient. Supabase needs time to exchange the code/hash for a session.
      const hasAuthParams = typeof window !== 'undefined' && (
        window.location.hash.includes('access_token') || 
        window.location.search.includes('code=')
      );

      const delay = (justSuccess || hasAuthParams) ? 15000 : isOAuthCallback ? 10000 : 8000;

      redirectTimer = setTimeout(() => {
        if (!user && !isPublic) {
          // One final check for auth params before giving up
          const stillHasParams = typeof window !== 'undefined' && (
            window.location.hash.includes('access_token') || 
            window.location.search.includes('code=')
          );
          
          if (stillHasParams) {
            console.log('[Auth] Auth params still present, extending grace period.');
            return;
          }

          console.warn('[Auth] Session not detected after grace period. Redirecting to login.');
          router.replace('/login');
        }
      }, delay);
    } else {
      if (isPublic && pathname !== '/') {
        router.replace('/');
      } else if (!user.onboardingCompleted && !pathname.startsWith(ONBOARDING_ROUTE) && !isOAuthCallback) {
        console.log('[Auth] Redirecting to onboarding');
        router.replace(ONBOARDING_ROUTE);
      } else if (user.onboardingCompleted && pathname.startsWith(ONBOARDING_ROUTE)) {
        router.replace('/');
      }
    }

    return () => clearTimeout(redirectTimer);
  }, [user, isLoading, pathname, router]);



  const login = useCallback(async (email: string, password: string): Promise<AuthResult> => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) return { success: false, message: error.message };
    if (!data.user) return { success: false, message: 'Identity missing.' };
    
    setUser(await syncProfile({ id: data.user.id, email: data.user.email, metadata: data.user.user_metadata }));
    return { success: true };
  }, [supabase, syncProfile]);

  const signup = useCallback(async (name: string, email: string, password: string): Promise<AuthResult> => {
    const { data, error } = await supabase.auth.signUp({ email, password, options: { data: { name } } });
    if (error) return { success: false, message: error.message };
    if (!data.user) return { success: false, message: 'Signup failed.' };

    setUser(await syncProfile({ id: data.user.id, email, metadata: { name } }));
    return { success: true };
  }, [supabase, syncProfile]);

  const logout = useCallback(async () => {
    clearCachedProfile();         // L7: clear cache so next login doesn't flash stale data
    resetPulseTimer();            // L8: reset pulse throttle (via hook export)
    await supabase.auth.signOut();
    setUser(null);
    router.replace('/login');
  }, [supabase, router]);

  const loginWithGoogle = useCallback(async (): Promise<AuthResult> => {
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo: typeof window !== 'undefined' ? `${window.location.origin}/auth/callback` : undefined,
      }
    });
    if (error) return { success: false, message: error.message };
    return { success: true };
  }, [supabase]);

  const loginWithGithub = useCallback(async (): Promise<AuthResult> => {
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'github',
      options: {
        redirectTo: typeof window !== 'undefined' ? `${window.location.origin}/auth/callback` : undefined,
      }
    });
    if (error) return { success: false, message: error.message };
    return { success: true };
  }, [supabase]);

  const loginWithDiscord = useCallback(async (): Promise<AuthResult> => {
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'discord',
      options: {
        redirectTo: typeof window !== 'undefined' ? `${window.location.origin}/auth/callback` : undefined,
      }
    });
    if (error) return { success: false, message: error.message };
    return { success: true };
  }, [supabase]);

  const resetPassword = useCallback(async (email: string): Promise<AuthResult> => {
    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: typeof window !== 'undefined' ? `${window.location.origin}/reset-password` : undefined,  // M6: SSR guard
    });
    if (error) return { success: false, message: error.message };
    return { success: true };
  }, [supabase]);

  /**
   * Updates mutable user profile fields.
   * L4 note: Only `name` (and avatar initial if it's a single char) are writable here.
   * Fields `plan`, `joinedDate`, `memoriesIndexed` are read-only — managed server-side.
   */
  const updateUser = useCallback(async (updates: Partial<User>): Promise<AuthResult> => {

    if (!user) return { success: false, message: 'Not authenticated' };

    try {
      const dbUpdates: { name?: string; avatar?: string; behavior_logging_consent?: boolean; onboarding_completed?: boolean } = {};
      const authUpdates: { name?: string } = {};

      if (updates.name) {
        dbUpdates.name = updates.name;
        authUpdates.name = updates.name;
      }

      if (updates.behaviorLoggingConsent !== undefined) {
        dbUpdates.behavior_logging_consent = updates.behaviorLoggingConsent;
      }
      
      if (updates.onboardingCompleted !== undefined) {
        dbUpdates.onboarding_completed = updates.onboardingCompleted;
      }
      
      // If current avatar is just an initial, update it to match the new name's initial
      if (user.avatar.length <= 2 && updates.name) {
        dbUpdates.avatar = updates.name.charAt(0).toUpperCase();
      }

      // 1. Update Auth Metadata first to ensure identity is consistent
      if (updates.name) {
        const { error: authError } = await supabase.auth.updateUser({
          data: authUpdates
        });
        if (authError) throw authError;
      }

      // 2. Update Database and GET the confirmed record back
      const { data: confirmed, error: dbError } = await supabase
        .from('user_profiles')
        .update(dbUpdates)
        .eq('user_id', user.id)
        .select('name,avatar,plan,joined_date,memories_indexed,behavior_logging_consent,onboarding_completed')
        .single();

      if (dbError) throw dbError;

      // 3. Update local state with the CONFIRMED data from the DB
      if (confirmed) {
        setUser(prev => prev ? {
          ...prev,
          name: confirmed.name,
          avatar: confirmed.avatar || confirmed.name.charAt(0).toUpperCase(),
          plan: confirmed.plan || prev.plan,
          memoriesIndexed: confirmed.memories_indexed || prev.memoriesIndexed,
          behaviorLoggingConsent: confirmed.behavior_logging_consent ?? prev.behaviorLoggingConsent,
          onboardingCompleted: confirmed.onboarding_completed ?? prev.onboardingCompleted,
        } : null);
      }
      
      return { success: true };
    } catch (err) {
      console.error('[Auth] Update failed:', err);
      return { success: false, message: getErrorMessage(err) };
    }
  }, [supabase, user]);

  const setGlobalTheme = useCallback((newTheme: 'dark' | 'light' | 'ember') => {
    setTheme(newTheme);
    if (typeof document !== 'undefined') document.documentElement.setAttribute('data-theme', newTheme); // L9: SSR guard
    localStorage.setItem('eyes-theme', newTheme);
  }, []);

  // Master Render
  if (isLoading && showAuthFallback) {
    return (
      <div className={styles.fallbackScreen}>
        <div className={styles.loaderLine} />
        <p>Initializing EYES Secure Session...</p>
      </div>
    );
  }

  if (isLoading) return null;

  const isPublic = PUBLIC_ROUTES.includes(pathname);
  if (!user && !isPublic) return null;

  const isGuestOnly = GUEST_ONLY_ROUTES.includes(pathname);
  if (user && isGuestOnly) return null;

  const isOAuthCallback = pathname.includes('/connect') || pathname.startsWith('/auth');

  // Prevent flash of Dashboard before redirect to onboarding completes
  if (user && !user.onboardingCompleted && !pathname.startsWith(ONBOARDING_ROUTE) && !isOAuthCallback) {
    return (
      <div className={styles.fallbackScreen}>
        <div className={styles.loaderLine} />
        <p>Preparing your experience...</p>
      </div>
    );
  }

  return (
    <AuthContext.Provider value={{ user, isLoading, login, signup, loginWithGoogle, loginWithGithub, loginWithDiscord, logout, resetPassword, supabase, updateUser, theme, setGlobalTheme }}>
      {children}
    </AuthContext.Provider>
  );
}

'use client';

/**
 * useAuthSession — handles initial session hydration, onAuthStateChange,
 * and the global unhandledrejection guard for refresh token failures.
 *
 * Extracted from AuthContext.tsx to reduce the 875-line monolith.
 */

import { useState, useEffect, useRef, useCallback } from 'react';
import type { AuthChangeEvent, Session } from '@supabase/supabase-js';
import type { SupabaseClient } from '@supabase/supabase-js';
import type { User } from '../AuthContext';

// ── Re-exported helpers (shared with AuthContext) ─────────────────────────────

export function isRefreshTokenFailure(message?: string) {
  const text = (message || '').toLowerCase();
  return (
    text.includes('invalid refresh token') ||
    text.includes('refresh token not found') ||
    (text.includes('refresh token') && text.includes('invalid'))
  );
}

export function isSupabaseLockStealFailure(message?: string) {
  const text = (message || '').toLowerCase();
  return (
    text.includes('was released because another request stole it') ||
    (text.includes('lock "lock:sb-') && text.includes('stole it'))
  );
}

export function getErrorMessage(error: unknown) {
  if (typeof error === 'string') return error;
  if (error && typeof error === 'object') {
    const detail = error as { message?: string; error_description?: string; error?: string; name?: string };
    const candidates = [detail.message, detail.error_description, detail.error, detail.name]
      .filter((v): v is string => Boolean(v && v.trim()));
    if (candidates.length > 0) return candidates.join(' ');
  }
  return String(error ?? '');
}

export function purgeSupabaseLocalAuthArtifacts() {
  if (typeof window === 'undefined') return;
  const supabaseRef = process.env.NEXT_PUBLIC_SUPABASE_URL?.split('//')[1]?.split('.')?.[0];
  const preferredKey = supabaseRef ? `sb-${supabaseRef}-auth-token` : null;
  [...Object.keys(window.localStorage), ...Object.keys(window.sessionStorage)].forEach((key) => {
    const isTarget = (preferredKey && key === preferredKey) || (key.startsWith('sb-') && key.endsWith('-auth-token'));
    if (isTarget) {
      window.localStorage.removeItem(key);
      window.sessionStorage.removeItem(key);
    }
  });
}

// ── Hook ──────────────────────────────────────────────────────────────────────

type SyncProfileFn = (authUser: { id: string; email?: string; metadata?: Record<string, unknown> }) => Promise<User>;

export function useAuthSession(
  supabase: SupabaseClient,
  syncProfile: SyncProfileFn,
  setUser: (user: User | null) => void,
  setIsLoading: (loading: boolean) => void,
) {
  const authInitStartedRef = useRef(false);
  const lastSyncedUserIdRef = useRef<string | null>(null);

  useEffect(() => {
    if (authInitStartedRef.current) return;
    authInitStartedRef.current = true;

    let mounted = true;

    // Global rejection guard for refresh token failures
    const handleUnhandledRejection = (event: PromiseRejectionEvent) => {
      const message = getErrorMessage(event.reason);
      if (isSupabaseLockStealFailure(message)) {
        event.preventDefault();
        console.warn('[Auth] Suppressing transient Supabase lock contention rejection.');
        return;
      }
      if (!isRefreshTokenFailure(message)) return;
      event.preventDefault();
      console.warn('[Auth] Unhandled refresh token rejection — purging local auth state.');
      void supabase.auth.signOut({ scope: 'local' }).catch(() => undefined);
      purgeSupabaseLocalAuthArtifacts();
      if (mounted) setUser(null);
    };

    if (typeof window !== 'undefined') {
      window.addEventListener('unhandledrejection', handleUnhandledRejection);
    }

    // Hard safety: never hang isLoading forever
    const safetyTimer = setTimeout(() => {
      if (!mounted) return;
      setIsLoading(false);
    }, 12000);

    // onAuthStateChange — primary event bus
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (event: AuthChangeEvent, session: Session | null) => {
        console.log('[Auth] State Event:', event);
        if (event === 'TOKEN_REFRESHED' || event === 'USER_UPDATED') return;

        if ((event === 'SIGNED_IN' || event === 'INITIAL_SESSION') && session?.user) {
          if (lastSyncedUserIdRef.current === session.user.id) {
            console.log('[Auth] Already synced this user, skipping duplicate event.');
            return;
          }
          lastSyncedUserIdRef.current = session.user.id;
          const profile = await syncProfile({
            id: session.user.id,
            email: session.user.email,
            metadata: session.user.user_metadata,
          });
          if (mounted) setUser(profile);
        } else if (event === 'SIGNED_OUT') {
          lastSyncedUserIdRef.current = null;
          if (mounted) setUser(null);
        }
      }
    );

    // Bootstrap from existing session
    const initialize = async () => {
      try {
        const sessionResult = await Promise.race([
          supabase.auth.getSession(),
          new Promise<null>((_, reject) => setTimeout(() => reject(new Error('Session timeout')), 9000)),
        ]) as { data: { session: Session | null }; error: { message?: string } | null } | null;

        if (!sessionResult) throw new Error('Session fetch timed out');

        const { data: { session }, error: sessionError } = sessionResult;
        if (sessionError) {
          if (isRefreshTokenFailure(sessionError.message)) {
            await supabase.auth.signOut({ scope: 'local' }).catch(() => undefined);
            purgeSupabaseLocalAuthArtifacts();
            if (mounted) setUser(null);
            return;
          }
          throw sessionError;
        }

        if (session?.user && mounted) {
          lastSyncedUserIdRef.current = session.user.id;
          const profile = await syncProfile({
            id: session.user.id,
            email: session.user.email,
            metadata: session.user.user_metadata,
          });
          if (mounted) setUser(profile);
        }
      } catch (err) {
        const message = getErrorMessage(err);
        if (isRefreshTokenFailure(message)) {
          await supabase.auth.signOut({ scope: 'local' }).catch(() => undefined);
          purgeSupabaseLocalAuthArtifacts();
        } else {
          console.error('[Auth] Initial session sync failed:', err);
        }
        if (mounted) setUser(null);
      } finally {
        if (mounted) {
          setIsLoading(false);
          clearTimeout(safetyTimer);
          console.log('[Auth] System Ready.');
        }
      }
    };

    initialize();

    return () => {
      mounted = false;
      clearTimeout(safetyTimer);
      if (typeof window !== 'undefined') window.removeEventListener('unhandledrejection', handleUnhandledRejection);
      subscription.unsubscribe();
    };
  }, [supabase, syncProfile, setUser, setIsLoading]);
}

// ── Realtime subscription hook ────────────────────────────────────────────────

let lastPulseTime = 0;
const PULSE_THROTTLE_MS = 10000;

export function emitRealtimeRefreshEvent() {
  if (typeof window === 'undefined') return;
  const now = Date.now();
  if (now - lastPulseTime < PULSE_THROTTLE_MS) return;
  lastPulseTime = now;
  window.dispatchEvent(new CustomEvent('eyes-realtime-refresh'));
}

export function resetPulseTimer() {
  lastPulseTime = 0;
}

export function useRealtimeSync(
  supabase: SupabaseClient,
  userId: string | null | undefined,
  isLoading: boolean,
  pathname: string,
) {
  useEffect(() => {
    if (isLoading || !userId) return;
    if (['/login', '/signup'].includes(pathname)) return;

    const watchedTables = ['sync_status', 'user_profiles', 'oauth_tokens'] as const;
    const channelName = `eyes-user-live:${userId}`;
    let refreshTimer: ReturnType<typeof setTimeout> | undefined;

    const queueRefresh = () => {
      if (refreshTimer) return;
      refreshTimer = setTimeout(() => {
        refreshTimer = undefined;
        emitRealtimeRefreshEvent();
      }, 2000);
    };

    let channel = supabase.channel(channelName);
    watchedTables.forEach((table) => {
      channel = channel.on(
        'postgres_changes',
        { event: '*', schema: 'public', table, filter: `user_id=eq.${userId}` },
        () => { queueRefresh(); }
      );
    });
    channel.subscribe();

    return () => {
      if (refreshTimer) clearTimeout(refreshTimer);
      void supabase.removeChannel(channel);
    };
  }, [isLoading, pathname, supabase, userId]);
}

// ── Background sync hook ───────────────────────────────────────────────────────

const AUTO_BACKGROUND_SYNC_ENABLED = process.env.NEXT_PUBLIC_AUTO_BACKGROUND_SYNC === 'true';

export function useBackgroundSync(
  supabase: SupabaseClient,
  userId: string | null | undefined,
  isLoading: boolean,
  pathname: string,
) {
  useEffect(() => {
    if (!AUTO_BACKGROUND_SYNC_ENABLED || isLoading || !userId) return;
    if (['/login', '/signup'].includes(pathname) || pathname.startsWith('/connect')) return;

    let cancelled = false;
    let syncInFlight = false;

    const runSync = async () => {
      if (cancelled || syncInFlight) return;
      if (typeof document !== 'undefined' && document.visibilityState === 'hidden') return;
      syncInFlight = true;
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) return;
        const response = await fetch('/api/sync/all?background=1', {
          method: 'POST',
          cache: 'no-store',
          keepalive: true,
          credentials: 'include',
        });
        if (!response.ok && response.status !== 202) {
          console.warn(`[Auth] Background sync returned ${response.status}.`);
        }
      } catch (err) {
        console.warn('[Auth] Background sync failed:', err);
      } finally {
        syncInFlight = false;
      }
    };

    const initialDelay = setTimeout(() => { void runSync(); }, 2500);
    const interval = setInterval(() => { void runSync(); }, 90000);
    const onVisibility = () => { if (document.visibilityState === 'visible') void runSync(); };

    if (typeof document !== 'undefined') document.addEventListener('visibilitychange', onVisibility);

    return () => {
      cancelled = true;
      clearTimeout(initialDelay);
      clearInterval(interval);
      if (typeof document !== 'undefined') document.removeEventListener('visibilitychange', onVisibility);
    };
  }, [isLoading, pathname, supabase, userId]);
}

import { createClient } from '@/utils/supabase/server';
import crypto from 'crypto';

/**
 * AI Gateway — Unified Production Interface (K1 + K2)
 *
 * K1: Zero provider SDKs. Every call goes through LITELLM_BASE_URL via one
 *     OpenAI-compatible fetch client.
 * K2: Only the four gateway aliases appear in code — never literal model strings.
 * K3: MOCK_MODE=true returns realistic fixtures so the product runs without keys.
 */

// ── Gateway config (K1) ─────────────────────────────────────────────────────
const getGatewayBase = () => (process.env.LITELLM_BASE_URL || '').replace(/\/$/, '');
const getGatewayKey = () => process.env.EYES_GATEWAY_KEY || process.env.LITELLM_KEY || '';

// ── Four gateway aliases (K2) ────────────────────────────────────────────────
const ALIAS_CHAT = 'auto-chat';
const ALIAS_EXTRACT = 'auto-extract';
const ALIAS_CLASSIFY = 'auto-classify';
const ALIAS_EMBED = 'auto-embed';

// ── Mock mode (K3) ───────────────────────────────────────────────────────────
const MOCK_MODE = process.env.MOCK_MODE === 'true';

// ── No fallbacks permitted (K1) ────────────────────────────────────────────────
// All calls route via the gateway.
const EMBED_DIMS = 1024; // Align with Voyage/Gemini 1024-dim database schema (Migration 032)

function pickRandom<T>(arr: T[]): T | null {
  return arr.length === 0 ? null : arr[Math.floor(Math.random() * arr.length)];
}
const sleep = (ms: number) => new Promise(r => setTimeout(r, ms));

// ── Per-model cooldown (in-process, resets on cold start) ────────────────────
const cooldowns = new Map<string, number>();
const COOLDOWN_MS = 300_000;
function isCooling(m: string): boolean {
  const t = cooldowns.get(m);
  if (!t) return false;
  if (Date.now() - t > COOLDOWN_MS) { cooldowns.delete(m); return false; }
  return true;
}
function markFailed(m: string): void { cooldowns.set(m, Date.now()); }

// ── Types ────────────────────────────────────────────────────────────────────
export type AIPreference = 'claude' | 'gemini' | 'auto';
export type AICapability = 'chat' | 'embed' | 'classify' | 'extract';

export interface AIHistoryMessage {
  role: 'user' | 'assistant' | 'system';
  content: string;
}

export interface AIInvokeOptions {
  capability: AICapability;
  messages?: AIHistoryMessage[];
  system?: string;
  preference?: AIPreference;
  capture?: boolean;
  maxTokens?: number;
  /** AbortSignal to cancel the in-flight request (e.g. when the chat timeout fires). */
  signal?: AbortSignal;
}

export type EmbedResult = { embedding: number[] };
export type InvokeResult = EmbedResult | string | null;

// ── K3 Mock fixtures ─────────────────────────────────────────────────────────
const MOCK_CHAT_FIXTURE = `Based on your digital history, there is a **contradiction** regarding the one-pager:

1. **The Commitment**: On March 14, you received an email from John (\`john@investornet.com\`) requesting your team's one-pager "by the end of the month" [gmail_8842].
2. **The Contradiction / Missing follow-through**: On April 2, you had a follow-up meeting on your Calendar ([cal_9120]) titled "Investor Network Meeting". However, there is no record in your sent emails of the one-pager being delivered prior to this meeting.
3. **Connecting the Dots**: We found a GitHub Pull Request ([gh_1122]) merged on March 20 where the one-pager draft was updated by your developer, but it was never emailed to John.

Would you like me to draft an email to John with the merged one-pager attached?`;

const MOCK_PLANNER_FIXTURE = JSON.stringify({
  queries: [{ q: 'sample query', sources: null, date_from: null, date_to: null, entities: null }],
  need_insights: false,
  is_note: false,
});

const MOCK_EMBED_FIXTURE: number[] = Array.from({ length: EMBED_DIMS }, (_, i) => Math.sin(i) * 0.01);

function mockResponse(capability: AICapability, system: string, messages: AIHistoryMessage[] = []): InvokeResult {
  if (capability === 'embed') return { embedding: MOCK_EMBED_FIXTURE };
  // Planner / classify calls return JSON
  if (system.includes('retrieval intent') || system.includes('classify') || /json only/i.test(system)) {
    return MOCK_PLANNER_FIXTURE;
  }

  const lastUserMsg = [...messages].reverse().find(m => m.role === 'user')?.content || '';
  const query = lastUserMsg.toLowerCase();

  if (query.includes('draft') || query.includes('yes') || query.includes('send') || query.includes('reply')) {
    return `Here is the drafted email to John:

**Subject:** Re: Investor Network Introduction & One-Pager

Hi John,

Thanks for the follow-up meeting on April 2nd. I apologize for the delay on this. Please find our team's latest updated one-pager attached (incorporating the changes from our GitHub update on March 20).

Let me know when you have time for a brief review.

Best,
[User]

*I have queued this draft in your Action Queue. You can approve it from the Connectors dashboard.*`;
  }

  if (query.includes('pr') || query.includes('github') || query.includes('pull request')) {
    return `The GitHub Pull Request [gh_1122] was titled "Update one-pager draft". It was merged by your developer on March 20th and included changes fixing typos and updating team bios in the one-pager document.`;
  }

  return MOCK_CHAT_FIXTURE;
}

// ── Gateway call (K1 — single OpenAI-compatible client) ──────────────────────
async function gatewayChat(
  alias: string,
  messages: { role: string; content: string }[],
  maxTokens = 1024,
  signal?: AbortSignal,
): Promise<string | null> {
  const base = getGatewayBase();
  const key = getGatewayKey();
  if (!base || !key) return null;
  try {
    const res = await fetch(`${base}/chat/completions`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${key}`,
      },
      body: JSON.stringify({ model: alias, messages, max_tokens: maxTokens, temperature: 0.1 }),
      signal, // thread AbortSignal through for cancellation on timeout
    });
    if (!res.ok) {
      console.warn(`[AI Gateway] ${alias} returned ${res.status}`);
      return null;
    }
    const body = await res.json();
    return body?.choices?.[0]?.message?.content ?? null;
  } catch (err) {
    if (err instanceof Error && err.name === 'AbortError') return null; // Clean cancellation
    console.warn('[AI Gateway] fetch failed:', err instanceof Error ? err.message : err);
    return null;
  }
}

async function gatewayEmbed(text: string, signal?: AbortSignal): Promise<number[] | null> {
  const base = getGatewayBase();
  const key = getGatewayKey();
  if (!base || !key) return null;
  try {
    const res = await fetch(`${base}/embeddings`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${key}`,
      },
      body: JSON.stringify({
        model: ALIAS_EMBED,
        input: text.slice(0, 8000),
        dimensions: 1024,
      }),
      signal, // thread AbortSignal through for cancellation on timeout
    });
    if (!res.ok) return null;
    const body = await res.json();
    return body?.data?.[0]?.embedding ?? null;
  } catch (err) {
    if (err instanceof Error && err.name === 'AbortError') return null; // Clean cancellation
    return null;
  }
}

// ── Embedding (gateway ONLY) ────────────────────────────────
async function handleEmbedding(text: string, signal?: AbortSignal): Promise<EmbedResult | null> {
  const gatewayResult = await gatewayEmbed(text, signal);
  if (gatewayResult) return { embedding: gatewayResult };
  console.error('[AI] Gateway embedding failed.');
  return null;
}
// ── Chat (gateway ONLY) ─────────────────────────
async function handleChat(
  messages: AIHistoryMessage[],
  system: string,
  capability: AICapability,
  overrideMaxTokens?: number,
  signal?: AbortSignal,
): Promise<string | null> {
  const isClassify = capability === 'classify' ||
    /return.*json|json only|valid json/i.test(system);
  const maxTokens = overrideMaxTokens ?? (isClassify ? 500 : 1024);

  const alias = isClassify ? ALIAS_CLASSIFY : (capability === 'extract' ? ALIAS_EXTRACT : ALIAS_CHAT);
  const history = messages
    .filter(m => m.role !== 'system')
    .map(m => ({ role: m.role === 'assistant' ? 'assistant' : 'user', content: m.content }));
  const fullMessages = [
    ...(system?.trim() ? [{ role: 'system', content: system }] : []),
    ...history,
  ];

  // 1. Gateway (K1)
  const gatewayResult = await gatewayChat(alias, fullMessages, maxTokens, signal);
  if (gatewayResult) { console.log(`[AI] Gateway (${alias}) OK`); return gatewayResult; }

  console.error('[AI] Gateway chat failed.');
  return null;
}

// ── Public interface ─────────────────────────────────────────────────────────
export async function invokeModel(options: AIInvokeOptions): Promise<InvokeResult> {
  const { capability, messages = [], system = '', preference: _pref = 'auto', capture = capability === 'chat', signal } = options;

  // K3: Mock mode
  if (MOCK_MODE) {
    console.log(`[AI] MOCK_MODE — returning fixture for ${capability}`);
    return mockResponse(capability, system, messages);
  }

  if (capability === 'embed') {
    return handleEmbedding(messages[0]?.content || '', signal);
  }

  const startedAt = Date.now();
  const result = await handleChat(messages, system, capability, options.maxTokens, signal);

  if (capture && result) {
    setTimeout(() => {
      captureBehavioralData({
        queryText: messages[messages.length - 1]?.content || '',
        queryType: capability,
        modelUsed: getGatewayBase() ? `gateway/${capability === 'classify' ? ALIAS_CLASSIFY : ALIAS_CHAT}` : 'fallback',
        latencyMs: Date.now() - startedAt,
        resultCount: messages.length,
        responseLength: result.length,
      }).catch(err => console.warn('[AI Behavioral] log failed:', err));
    }, 0);
  }

  return result;
}

// ── Streaming (gateway SSE ONLY) ──────────────
export async function invokeModelStream(options: AIInvokeOptions): Promise<ReadableStream> {
  const { messages = [], system = '', signal } = options;
  const encoder = new TextEncoder();

  if (MOCK_MODE) {
    const mockText = mockResponse('chat', system, messages) as string;
    return new ReadableStream({
      start(controller) {
        controller.enqueue(encoder.encode(mockText));
        controller.close();
      },
    });
  }

  const history = messages
    .filter(m => m.role !== 'system')
    .map(m => ({ role: m.role === 'assistant' ? 'assistant' : 'user', content: m.content }));
  const fullMessages = [
    ...(system?.trim() ? [{ role: 'system', content: system }] : []),
    ...history,
  ];

  // 1. Gateway stream
  const base = getGatewayBase();
  const key = getGatewayKey();
  if (base && key) {
    try {
      const res = await fetch(`${base}/chat/completions`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${key}` },
        body: JSON.stringify({ model: ALIAS_CHAT, messages: fullMessages, max_tokens: 1024, temperature: 0.1, stream: true }),
        signal, // propagate AbortSignal so timeout cancels the stream
      });
      if (res.ok && res.body) {
        console.log('[AI Stream] Gateway streaming');
        return sseToReadable(res.body, encoder);
      }
    } catch (err) {
      if (err instanceof Error && err.name === 'AbortError') {
        // Clean cancellation — return an empty stream
        return new ReadableStream({ start(c) { c.close(); } });
      }
      console.warn('[AI Stream] Gateway stream failed:', err instanceof Error ? err.message : err);
    }
  }

  return new ReadableStream({
    async start(controller) {
      controller.enqueue(encoder.encode('\n\n[SYSTEM] Gateway unavailable.'));
      controller.close();
    },
  });
}

/** Parse SSE stream into a ReadableStream of text deltas */
function sseToReadable(body: ReadableStream<Uint8Array>, encoder: TextEncoder): ReadableStream {
  return new ReadableStream({
    async start(controller) {
      const reader = body.getReader();
      const decoder = new TextDecoder();
      try {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          for (const line of decoder.decode(value, { stream: true }).split('\n')) {
            const t = line.trim();
            if (!t.startsWith('data:')) continue;
            const d = t.slice(5).trim();
            if (d === '[DONE]') break;
            try {
              const delta = JSON.parse(d)?.choices?.[0]?.delta?.content;
              if (delta) controller.enqueue(encoder.encode(delta));
            } catch { /* malformed SSE */ }
          }
        }
      } catch (e) { console.warn('[AI SSE] read error:', e); }
      finally { controller.close(); }
    },
  });
}

// ── Legacy wrappers ──────────────────────────────────────────────────────────
export async function generateEmbedding(text: string) {
  return invokeModel({ capability: 'embed', messages: [{ role: 'user', content: text }] });
}

export async function chatCompletion(messages: AIHistoryMessage[]): Promise<string | null> {
  const result = await invokeModel({ capability: 'chat', messages });
  return typeof result === 'string' ? result : null;
}

export async function chatCompletionStream(messages: AIHistoryMessage[]) {
  return invokeModelStream({ capability: 'chat', messages });
}

// ── Behavioural logging ──────────────────────────────────────────────────────
async function captureBehavioralData(data: {
  queryText: string; queryType: string; modelUsed: string;
  latencyMs: number; resultCount: number; responseLength: number;
}) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    const { data: profile } = await supabase
      .from('user_profiles').select('behavior_logging_consent')
      .eq('user_id', user.id).maybeSingle();
    if (profile?.behavior_logging_consent === false) return;

    const salt = process.env.BEHAVIOR_SALT;
    if (!salt && process.env.NODE_ENV === 'production') {
      console.warn('[AI Behavioral] BEHAVIOR_SALT not set.');
    }
    const userHash = crypto.createHash('sha256').update(user.id + (salt || 'eyes-salt')).digest('hex');

    const hour = new Date().getHours();
    const bucket = hour < 12 ? 'morning' : hour < 17 ? 'afternoon' : hour < 21 ? 'evening' : 'night';

    await supabase.from('query_behavior').insert({
      user_hash: userHash,
      query_text: data.queryText.slice(0, 50),
      query_type: data.queryType,
      model_used: data.modelUsed,
      latency_ms: data.latencyMs,
      result_count: data.resultCount,
      response_length: data.responseLength,
      sources_used: [],
      coarse_geography: 'unknown',
      coarse_time_bucket: bucket,
    });
  } catch (err) {
    console.warn('[AI Behavioral] Logging failed:', err);
  }
}

import { SEEDED_PATTERNS, SeededPattern } from '../../config/seed_patterns';

/**
 * Represents the structured graph data extracted by the Chronic Layer (GLiNER/GLiREL).
 * This will eventually be queried directly from Neo4j.
 */
export interface UserGraphData {
  userId: string;
  entities: {
    projects: string[];
    commitments: string[];
    goals: string[];
    people: string[];
  };
  metrics: {
    commitmentsToOthersCompleted: number;
    commitmentsToOthersTotal: number;
    commitmentsToSelfCompleted: number;
    commitmentsToSelfTotal: number;
    projectsStarted: number;
    projectsShipped: number;
    researchMentions: number;
  };
  recentEdges: { head: string; label: string; tail: string }[];
}

export interface PatternMatchResult {
  pattern: SeededPattern;
  confidence: number; // 0.0 to 1.0
  evidence: string[]; // Specific graph nodes/edges that triggered this
}

/**
 * Signal Detection Engine
 * Evaluates the user's raw graph data against the Seeded Pattern Library to detect early life-shapes.
 */
export class PatternMatcher {

  /**
   * Evaluates the Cold Start patterns for a user based on their initial data sync.
   * @param graphData The raw entities and relations extracted from the user's first sync.
   * @returns An array of matched patterns with confidence scores.
   */
  public static evaluateColdStart(graphData: UserGraphData): PatternMatchResult[] {
    const matches: PatternMatchResult[] = [];

    // 1. Evaluate THE_LOOP (The Builder's Loop)
    if (graphData.metrics.projectsStarted >= 3 && graphData.metrics.projectsShipped === 0) {
      matches.push({
        pattern: SEEDED_PATTERNS.find(p => p.code === 'THE_LOOP')!,
        confidence: 0.85,
        evidence: [
          `Detected ${graphData.metrics.projectsStarted} started projects.`,
          `Detected 0 shipped/completed projects.`,
          `Projects: ${graphData.entities.projects.join(', ')}`
        ]
      });
    }

    // 2. Evaluate ORBIT (Executes for Others, Orbits Own Work)
    const otherCompletionRate = graphData.metrics.commitmentsToOthersTotal > 0 
      ? graphData.metrics.commitmentsToOthersCompleted / graphData.metrics.commitmentsToOthersTotal 
      : 0;

    const selfCompletionRate = graphData.metrics.commitmentsToSelfTotal > 0 
      ? graphData.metrics.commitmentsToSelfCompleted / graphData.metrics.commitmentsToSelfTotal 
      : 0;

    if (otherCompletionRate > 0.8 && selfCompletionRate < 0.3 && graphData.metrics.commitmentsToSelfTotal > 2) {
      matches.push({
        pattern: SEEDED_PATTERNS.find(p => p.code === 'ORBIT')!,
        confidence: 0.9,
        evidence: [
          `Completion rate for external commitments: ${(otherCompletionRate * 100).toFixed(0)}%`,
          `Completion rate for internal/self commitments: ${(selfCompletionRate * 100).toFixed(0)}%`
        ]
      });
    }

    // 3. Evaluate AVOIDANCE (Avoidance-via-Research)
    if (graphData.metrics.researchMentions > 10 && selfCompletionRate < 0.3) {
       matches.push({
        pattern: SEEDED_PATTERNS.find(p => p.code === 'AVOIDANCE')!,
        confidence: 0.75,
        evidence: [
          `High volume of research/learning mentions (${graphData.metrics.researchMentions}).`,
          `Co-occurring with stalled self-directed commitments.`
        ]
      });
    }

    // (Additional pattern detection logic will be wired here as the graph schema expands)

    return matches;
  }

  /**
   * The Confirms / Disconfirms Loop (Pending Phase 2 Graph DB)
   * This will be called periodically to re-evaluate prior hypotheses against new data.
   */
  public static validateOngoingPatterns(userId: string, currentMatches: PatternMatchResult[], newGraphData: UserGraphData) {
    // TODO: Implement temporal drift analysis and edge invalidation.
    // This requires the Neo4j temporal graph to be active.
    throw new Error("validateOngoingPatterns requires active Graph DB connection.");
  }
}

import type { SupabaseClient } from '@supabase/supabase-js';
import { classifyContentType, processAcuteDetection } from '@/services/acute/detection';

type PostgrestErrorLike = {
  code?: string;
  message?: string;
};

const MISSING_CONFLICT_CONSTRAINT_CODE = '42P10';

function hasMissingConflictConstraint(error: PostgrestErrorLike | null) {
  return error?.code === MISSING_CONFLICT_CONSTRAINT_CODE;
}

function eventIdentityKey(event: RawEventUpsertRow) {
  return `${event.user_id}::${event.platform}::${event.platform_id}`;
}

export type RawEventUpsertRow = {
  user_id: string;
  platform: string;
  platform_id: string;
  event_type: string;
  title: string;
  content: string;
  author: string;
  timestamp: string;
  metadata: Record<string, unknown>;
  is_flagged: boolean;
  flag_severity: string | null;
  flag_reason: string | null;
};

export type SyncStatusUpsertRow = {
  user_id: string;
  platform: string;
  status?: string;
  sync_progress?: number;
  total_items?: number;
  last_sync_at?: string;
  next_sync_at?: string;
  error_message?: string | null;
  cursor?: string | null;
  metadata?: Record<string, unknown>;
};

export async function upsertRawEventsSafely(supabase: SupabaseClient, events: Record<string, unknown>[]) {
  if (events.length === 0) {
    return;
  }

  // Cast to typed rows — field shapes are enforced by construction in every sync route.
  const dedupedEvents = Array.from(
    new Map((events as RawEventUpsertRow[]).map((event) => [eventIdentityKey(event), event])).values()
  );

  // Map RawEventUpsertRow fields to the memories table schema
  // Key difference: platform_id (raw_events) → source_id (memories)
  const memoryRows = dedupedEvents.map((event) => {
    // Auto-classify content_type for drift detection (§2.2)
    const contentType = classifyContentType({
      platform: event.platform,
      content: event.content,
      is_outbound: event.metadata?.is_outbound === true,
      event_type: event.event_type,
    });
    // Auto-compute date_bucket for state vector aggregation (§2.2)
    const dateBucket = event.timestamp
      ? new Date(event.timestamp).toISOString().split('T')[0]
      : new Date().toISOString().split('T')[0];

    return {
      user_id: event.user_id,
      platform: event.platform,
      source_id: event.platform_id,
      event_type: event.event_type,
      title: event.title,
      content: event.content,
      author: event.author,
      timestamp: event.timestamp,
      metadata: event.metadata,
      is_flagged: event.is_flagged,
      flag_severity: event.flag_severity,
      flag_reason: event.flag_reason,
      content_type: contentType,
      date_bucket: dateBucket,
    };
  });

  const { error: upsertError } = await supabase
    .from('memories')
    .upsert(memoryRows, { onConflict: 'user_id,platform,source_id' });

  if (!upsertError) {
    // Fire acute detection asynchronously (non-blocking)
    fireAcuteDetection(supabase, dedupedEvents).catch(() => {});
    // Fire entity extraction asynchronously (non-blocking)
    fireEntityExtraction(supabase, dedupedEvents).catch(() => {});
    return;
  }

  if (!hasMissingConflictConstraint(upsertError)) {
    throw upsertError;
  }

  console.warn(
    '[DB] memories upsert fallback activated because ON CONFLICT constraint is missing. Apply latest migrations.'
  );

  const groupedIds = new Map<string, { userId: string; platform: string; ids: string[] }>();

  dedupedEvents.forEach((event) => {
    const groupKey = `${event.user_id}::${event.platform}`;
    const group = groupedIds.get(groupKey);
    if (!group) {
      groupedIds.set(groupKey, {
        userId: event.user_id,
        platform: event.platform,
        ids: [event.platform_id],
      });
      return;
    }
    group.ids.push(event.platform_id);
  });

  for (const group of groupedIds.values()) {
    const uniqueIds = Array.from(new Set(group.ids));
    if (uniqueIds.length === 0) continue;

    const { error: deleteError } = await supabase
      .from('memories')
      .delete()
      .eq('user_id', group.userId)
      .eq('platform', group.platform)
      .in('source_id', uniqueIds);

    if (deleteError) throw deleteError;
  }

  const { error: insertError } = await supabase.from('memories').insert(memoryRows);
  if (insertError) throw insertError;

  // Fire acute detection asynchronously (non-blocking)
  fireAcuteDetection(supabase, dedupedEvents).catch(() => {});
  // Fire entity extraction asynchronously (non-blocking)
  fireEntityExtraction(supabase, dedupedEvents).catch(() => {});
}

/**
 * Fire-and-forget acute detection on recently ingested events.
 * Runs in background — never blocks the sync response.
 */
async function fireAcuteDetection(supabase: SupabaseClient, events: RawEventUpsertRow[]) {
  try {
    const acuteEvents = events.map(e => ({
      id: `${e.user_id}-${e.platform}-${e.platform_id}`,
      user_id: e.user_id,
      platform: e.platform,
      title: e.title,
      content: e.content,
      author: e.author,
      timestamp: e.timestamp,
      is_outbound: e.metadata?.is_outbound === true,
    }));
    await processAcuteDetection(supabase, acuteEvents);
  } catch (err) {
    console.warn('[Acute] Background detection failed (non-fatal):', err);
  }
}

/**
 * Fire-and-forget entity extraction on recently ingested events.
 * Sends data to the new Python FastAPI Chronic Engine running locally.
 */
async function fireEntityExtraction(supabase: SupabaseClient, events: RawEventUpsertRow[]) {
  const CHRONIC_ENGINE_URL = process.env.CHRONIC_ENGINE_URL || 'http://127.0.0.1:8000';
  
  try {
    // Phase 3.A: Process ALL synced events regardless of platform
    const eligible = events.filter(e => e.content && e.content.length >= 80);
    if (eligible.length === 0) return;

    for (const event of eligible) {
      try {
        const response = await fetch(`${CHRONIC_ENGINE_URL}/extract`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            user_id: event.user_id,
            platform_id: event.platform_id,
            text: event.content.slice(0, 2000), // Send first 2000 chars to GLiNER
            threshold: 0.6
          })
        });

        if (!response.ok) {
          console.warn(`[Entities] Chronic Engine returned ${response.status}`);
          continue;
        }

        const data = await response.json();
        const entities = data.entities || [];
        const relations = data.relations || [];

        if (!entities.length && !relations.length) continue;

        // Store the raw output from GLiNER in the memories table (including start/end indices for Anchoring)
        await supabase
          .from('memories')
          .update({ 
            entities_extracted: entities,
            is_graph_extracted: true
          })
          .eq('user_id', event.user_id)
          .eq('platform', event.platform)
          .eq('source_id', event.platform_id);

        // Save relationships to the Bi-Temporal Graph table (Phase 2)
        if (relations.length > 0) {
          const edgesToInsert = relations.map((rel: any) => ({
             user_id: event.user_id,
             head_node_id: rel.head.toLowerCase().replace(/\s+/g, '_'),
             tail_node_id: rel.tail.toLowerCase().replace(/\s+/g, '_'),
             relation_label: rel.label,
             confidence: rel.score,
             observed_from: new Date().toISOString(),
             source_record_id: event.platform_id
          }));

          const { error: edgeError } = await supabase.from('chronic_edges').insert(edgesToInsert);
          if (edgeError) {
             console.warn('[Chronic Engine] Failed to save edges to Supabase:', edgeError.message);
          }
        }

        console.log(`[Chronic Engine] Successfully extracted ${entities.length} entities & ${relations.length} relations from ${event.platform}/${event.platform_id.slice(0, 12)} via FastAPI`);
      } catch (err) {
        console.warn('[Chronic Engine] Fetch failed (is the Python server running?):', err);
      }
    }
  } catch (err) {
    console.warn('[Chronic Engine] Background extraction failed:', err);
  }
}

export async function upsertSyncStatusSafely(supabase: SupabaseClient, syncStatus: SyncStatusUpsertRow) {
  const { error: upsertError } = await supabase
    .from('sync_status')
    .upsert(syncStatus, { onConflict: 'user_id,platform' });

  if (!upsertError) return;

  if (!hasMissingConflictConstraint(upsertError)) {
    console.error(`[DB Error] Sync status upsert failed: ${upsertError.message}`);
    throw upsertError;
  }

  // Fallback for missing constraints
  const { error: updateError } = await supabase
    .from('sync_status')
    .update(syncStatus)
    .eq('user_id', syncStatus.user_id)
    .eq('platform', syncStatus.platform);

  if (updateError) throw updateError;
}

/**
 * Batch upsert multiple sync status rows in a single operation.
 * Significantly reduces database load compared to individual upserts.
 * Work Item #4: Status Table Write Batching
 */
export async function batchUpsertSyncStatus(supabase: SupabaseClient, statuses: SyncStatusUpsertRow[]) {
  if (statuses.length === 0) return;

  // Deduplicate by user_id+platform composite key (keep last)
  const dedupedMap = new Map<string, SyncStatusUpsertRow>();
  for (const status of statuses) {
    const key = `${status.user_id}::${status.platform}`;
    dedupedMap.set(key, status);
  }

  const dedupedStatuses = Array.from(dedupedMap.values());

  try {
    const { error: upsertError } = await supabase
      .from('sync_status')
      .upsert(dedupedStatuses, { onConflict: 'user_id,platform' });

    if (!upsertError) return;

    if (!hasMissingConflictConstraint(upsertError)) {
      console.error(`[DB Error] Batch sync status upsert failed: ${upsertError.message}`);
      throw upsertError;
    }

    // Fallback: individual updates if batch fails
    console.warn('[DB] Batch sync status upsert failed, falling back to individual updates');
    for (const status of dedupedStatuses) {
      await upsertSyncStatusSafely(supabase, status);
    }
  } catch (error) {
    console.error('[DB] Batch status upsert error:', error);
    throw error;
  }
}

/**
 * Webhook escalation utilities - Work Item #6: Webhook Escalation Tuning
 * Optimizes payload sizes, batching, and retry timing for escalation webhooks
 */

interface WebhookPayload {
  service: string;
  event: string;
  emittedAt: string;
  runId: string;
  userId: string;
  code: string;
  severity: 'warning' | 'critical';
  owner: string;
  message: string;
  observed: number;
  threshold: number;
  metrics: Record<string, unknown>;
}

interface OptimizedWebhookPayload {
  service: string;
  event: string;
  t: string; // timestamp (compact)
  r: string; // runId (compact)
  u: string; // userId (compact)
  c: string; // code
  s: 'w' | 'c'; // severity (compact: w=warning, c=critical)
  o: string; // owner
  m: string; // message
  ob: number; // observed
  th: number; // threshold
  // metrics included only if they contain critical thresholds
  mt?: {
    pr?: number; // pendingRetries (only if > 0)
    dl?: number; // deadLetters24h (only if > 0)
    fr?: number; // failureRate24h (as percentage 0-100, only if > 0)
  };
}

/**
 * Optimize webhook payload to reduce transmission size
 * Work Item #6: Reduces payload by ~50% through field compaction
 */
export function optimizeWebhookPayload(payload: WebhookPayload): OptimizedWebhookPayload {
  const metrics = payload.metrics || {};
  const optimized: OptimizedWebhookPayload = {
    service: payload.service,
    event: payload.event,
    t: payload.emittedAt,
    r: payload.runId.slice(0, 8), // Use first 8 chars of UUID
    u: payload.userId.slice(0, 8),
    c: payload.code,
    s: payload.severity === 'critical' ? 'c' : 'w',
    o: payload.owner,
    m: payload.message.slice(0, 200), // Truncate message to 200 chars
    ob: payload.observed,
    th: payload.threshold,
  };

  // Include metrics only if they have critical values
  const compactMetrics: OptimizedWebhookPayload['mt'] = {};
  let hasMetrics = false;

  if (typeof metrics === 'object' && metrics !== null) {
    const metricsRecord = metrics as Record<string, unknown>;
    const pendingRetries = metricsRecord['pendingRetries'];
    if (typeof pendingRetries === 'number' && pendingRetries > 0) {
      compactMetrics.pr = pendingRetries;
      hasMetrics = true;
    }

    const deadLetters = metricsRecord['deadLetters24h'];
    if (typeof deadLetters === 'number' && deadLetters > 0) {
      compactMetrics.dl = deadLetters;
      hasMetrics = true;
    }

    const failureRate = metricsRecord['failureRate24h'];
    if (typeof failureRate === 'number' && failureRate > 0) {
      // Convert to percentage (0-100)
      compactMetrics.fr = Math.round(failureRate * 100);
      hasMetrics = true;
    }
  }

  if (hasMetrics) {
    optimized.mt = compactMetrics;
  }

  return optimized;
}

/**
 * Restore optimized payload to original format for backward compatibility
 * Work Item #6: Decompression utility
 */
export function restoreWebhookPayload(optimized: OptimizedWebhookPayload): WebhookPayload {
  const mt = optimized.mt || {};
  return {
    service: optimized.service,
    event: optimized.event,
    emittedAt: optimized.t,
    runId: optimized.r,
    userId: optimized.u,
    code: optimized.c,
    severity: optimized.s === 'c' ? 'critical' : 'warning',
    owner: optimized.o,
    message: optimized.m,
    observed: optimized.ob,
    threshold: optimized.th,
    metrics: {
      pendingRetries: mt.pr || 0,
      deadLetters24h: mt.dl || 0,
      failureRate24h: (mt.fr ?? 0) / 100,
    },
  };
}

/**
 * Batch multiple escalations into a single webhook call
 * Work Item #6: Reduces number of outbound requests
 */
export interface BatchedWebhookPayload {
  service: string;
  event: string;
  emittedAt: string;
  runId: string;
  escalations: OptimizedWebhookPayload[];
  count: number;
}

export function batchWebhookPayloads(
  payloads: WebhookPayload[],
  runId: string
): BatchedWebhookPayload {
  return {
    service: 'the-eyes',
    event: 'sync-escalation-batch',
    emittedAt: new Date().toISOString(),
    runId,
    escalations: payloads.map(optimizeWebhookPayload),
    count: payloads.length,
  };
}

/**
 * Calculate backoff delay for webhook retry
 * Work Item #6: Exponential backoff with jitter
 */
export function calculateWebhookRetryDelay(
  attemptNumber: number,
  baseDelayMs: number = 1000
): number {
  const exponent = Math.min(attemptNumber, 5); // Cap at 5 to avoid huge delays
  const delay = baseDelayMs * Math.pow(2, exponent);
  const jitter = Math.random() * delay * 0.1; // 10% jitter
  return Math.floor(delay + jitter);
}

/**
 * Check if webhook error is retriable
 * Work Item #6: Distinguishes transient from permanent failures
 */
export function isRetriableWebhookError(status: number | null, _error: string | null): boolean {
  if (status === null) {
    // Network error - retriable
    return true;
  }

  if (status >= 500) {
    // Server error - retriable
    return true;
  }

  if (status === 429) {
    // Rate limited - retriable with backoff
    return true;
  }

  if (status === 408) {
    // Request timeout - retriable
    return true;
  }

  // 4xx client errors (except 408) are not retriable
  // 3xx redirects are not retriable (should be resolved by fetch)
  // 2xx successes are not errors
  return false;
}

/**
 * Calculate webhook dispatch cooldown
 * Work Item #6: Prevents escalation spam
 */
export function calculateEscalationCooldown(
  dispatchCount: number,
  baseCooldownMinutes: number = 60
): number {
  // Linear backoff: first dispatch cooldown is base, second is 2x, etc.
  const cooldownMinutes = baseCooldownMinutes * Math.min(dispatchCount + 1, 5);
  return cooldownMinutes * 60 * 1000; // Convert to milliseconds
}

/**
 * Get webhook timeout based on escalation severity
 * Work Item #6: Critical escalations get more time
 */
export function getWebhookTimeoutMs(severity: 'warning' | 'critical'): number {
  // Critical escalations get 10s timeout, warnings get 5s
  return severity === 'critical' ? 10000 : 5000;
}

/**
 * Format webhook dispatch error for logging
 * Work Item #6: Better observability
 */
export interface WebhookDispatchError {
  code: string;
  severity: string;
  status: number | null;
  message: string;
  retriable: boolean;
  timestamp: string;
}

export function createWebhookDispatchError(
  code: string,
  severity: string,
  status: number | null,
  errorMessage: string
): WebhookDispatchError {
  return {
    code,
    severity,
    status,
    message: errorMessage.slice(0, 200),
    retriable: isRetriableWebhookError(status, errorMessage),
    timestamp: new Date().toISOString(),
  };
}
